export type Arcana = 'major' | 'minor';
export type Suit = 'cups' | 'wands' | 'swords' | 'pentacles';
export type YesNo = 'yes' | 'no' | 'neutral';

export interface TarotCard {
  id: string;
  name: string;
  name_zh: string;
  number: number;
  arcana: Arcana;
  suit?: Suit;
  keywords: string[];
  upright: { meaning: string; love: string; career: string; advice: string };
  reversed: { meaning: string; love: string; career: string; advice: string };
  element: string;
  color: string; // accent color hex
  // Enriched fields from labyrinthos.co
  astrology: string;
  yes_no: YesNo;
  upright_general: string;
  reversed_general: string;
  upright_love_en: string;
  reversed_love_en: string;
  upright_career_en: string;
  reversed_career_en: string;
  upright_finance_en: string;
  reversed_finance_en: string;
}

