const MINOR_ENRICHED: Record<string, {
  astrology: string; yes_no: string;
  upright_general: string; reversed_general: string;
  upright_love_en: string; reversed_love_en: string;
  upright_career_en: string; reversed_career_en: string;
  upright_finance_en: string; reversed_finance_en: string;
}> = {
  'cups-1': {
    astrology: '',
    yes_no: 'yes',
    upright_general: 'Getting the Ace of Cups upright shows that it\'s time to let loose of whatever emotional baggage you have and start living your life to the fullest. Like with all the other aces, there is a new beginning that is indicated here - a chance to start fresh. It might come in the form of opening yourself up to the possibilities of new relationships, romantic or otherwise, that have the ability to make you emotionally fulfilled. The release indicated by this card may either be spiritual or emotional, depending on what you are going through. The Ace of Cups may come to a reading after a long period of being lonely or enduring something that deeply hurt you emotionally, and it\'s appearance may be there to herald the turning over a new leaf.',
    reversed_general: '',
    upright_love_en: 'One of happiest cards to get in a love tarot reading, the Ace of Cups suggests the awakening of new feelings. Should you be single, you may find yourself developing a new romantic relationship, or a friendship that will be deeply meaningful to you. If you are already in a relationship, a new stage of intimacy, compassion and understanding can be reached between the two of you. The Ace of Cups tarot love meaning signals there is an opportunity for you now to grow emotionally, spiritually and creatively, should you take the cup and drink. At this time, decisions made from feelings and intuition are favored; learn to trust what your gut says and avoid over-analyzing situations.',
    reversed_love_en: 'Some sadness and emotional upset can be signaled by the reversed Ace of Cups tarot love meaning. This may have stemmed from an argument or even a break up, leaving you to feel alone and vulnerable. This card can also simply mean feeling a bit somber about your current relationship, or perhaps having a temporary loss of faith. Something is blocking you from being able to experience, give and receive true love. You may not be meeting your partner, or others in general, with an open heart. It is likely that insecurity is playing a strong role; we must all be able to love ourselves before we can truly love another person. Try and look inward, and give yourself the love that you want before seeking it in another.',
    upright_career_en: 'The upright Ace of Cups is a sign of both new emotional beginnings and friendly intentions. When it comes to your career, these principles can take shape here in a number of ways. If you are searching for a job, this card can mark a new start when it comes to your work. It may not always imply a new job, but can signify happy relations between you and your colleagues, or also an emotional awakening when it comes to how you perceive your work. New projects can be a wellspring of creativity. This is a good time to embark on new challenges and tasks, as you utilize this rush of inspiration. If you have been afraid of taking on more responsibilities, now is the moment to push past these fears; this is particularly true if you work in a creative field.',
    reversed_career_en: 'When reversed, the good news and comradery of the Ace of Cups is subverted. For those who are searching for a new position, you may be disappointed. There may be some negative emotions surrounding your work. You may find frustration and obstacles, as well as a feeling of emptiness when it comes to your job. Whatever the reason is, you may likely also feel uninspired and unmotivated at work right now. Sometimes, as the cups also rule relationships, you may find that co-workers can be less friendly and helpful at this time. Do your best to weather the storm and find motivation where possible. If nothing else, try to remember that work is only one aspect of your life, not everything.',
    upright_finance_en: 'The friendly and sociable quality of the Ace of Cups can have an effect on your financial situation as well. As people are more accommodating to you, they are more likely to offer the financial support you request. This support is most often in the form of approved loans or mortgages, but can also come in the form of support from family members and friends. This card can be especially comforting to those who have been searching for help. Sometimes, this card can also suggest a new wave of creativity when it comes to making money. If this doesn’t quite apply to you, this card can also generally signify financial stability, and the emotional contentment that comes from it.',
    reversed_finance_en: 'With the reversed Ace of Cups, you may get news that you don’t quite want to hear when it comes to your finances. If you applied to take out a loan or receive a grant, there may be some disappointment headed your way. Perhaps asking for assistance from family or friends has not yielded any results either. If none of these situations apply to you, you may just be dealing with some feelings of ambivalence or frustration when it comes to your financial situation. Let yourself feel, but not be consumed by these emotions.',
  },
  'cups-2': {
    astrology: '',
    yes_no: 'yes',
    upright_general: 'To see the Two of Cups is an indication of a partnership that is built on the union of forces, a strong connection and a balanced and equal partnership. The exchange of cups suggest that each party\'s emotions are intertwined with the other\'s, and each participant\'s feelings have profound affects on the other. A strong pair is indicated here, the joy of two becoming one.',
    reversed_general: '',
    upright_love_en: 'Attraction and coming together is signaled by the 2 of Cups tarot love meaning. This card encourages the beginnings of partnerships of any kind, and the harmony that arises when two people come together to work in unity. This card also suggest a relationship that is mutually beneficial, one where the partners encourage one another to do their very best. If you’re already in a relationship, you may find that this time brings better communication, balance and amicability. You may be able to better cooperate at this time. Try and be aware of your partners and your own talents; give each other trust to do things that are your strengths. The 2 of Cups is all about partnerships that build up each individual person, while being together.',
    reversed_love_en: 'Something isn’t quite right when the reversed 2 of Cups card shows up in a love tarot reading. Either the two of you are becoming too co-dependent on each other, unable to develop each person’s unique talents, or the balance between two partners can be upset with uneven power dynamics. If you’re in a relationship, always make sure to nurture your own and your partner’s individuality; the two of you are different people, with different interests and needs. Being who you are, on your own, will bring more to the relationship than if you were identical to your partner. Sometimes, this card can also point to the pursuit of love at the expense of all else.',
    upright_career_en: 'The upright 2 of Cups is strongly associated with positive relationships, meaning that when it comes to your career, you may find that your relationships with your colleagues or business partners can be particularly strong right now. You may find support and harmony in the people around you. It should be especially comforting to those who were debating starting a business partnership. The card signifies that this new partnership will be fruitful and that you will work well together. Oftentimes, the two of cups is associated with romantic relationships, but this is very rarely applicable to the career setting, but if you have recently been interested in someone you met through work, it can also signal happiness in that relationship as well. Just be aware of the risks when it comes to mixing pleasure and work.',
    reversed_career_en: 'While the upright two of cups is indicative of strong, positive relationships, the opposite is true of the reversed two of cups. If you are in a business partnership, you may be dealing with diverging interests, conflicts or a lack of respect. If you do not yet have a partnership but were looking to form one, this is a warning to be cautious.The other person may not value you or share your goals. If you are not in or trying to start a business partnership, it is likely that those with whom you work can be otherwise combative right now. You might find insubordination if you are a leader, or general tension and coldness from your colleagues.',
    upright_finance_en: 'The two of cups can suggest stable financial situations; this doesn’t quite signal wealth, but it indicates financial security for a period of time. It would be unwise to treat this card as a sign of boundless fortune, since pointedly, this card is rather instead about reliability. As the twos always signal balance, it is likely that you’ll be having enough funds coming in to cover what you spend. It is however still advised to be wise with your money so that this period of stability will last. If you spend outside of your means or are otherwise reckless, there is no reason to believe those behaviors would go unpunished. Instead of spending, take a moment to remind yourself that you are not under financial stress right now, that is its own reward.',
    reversed_finance_en: 'The reversed two of cups is not a spectacular card for finances. Instead, it indicates that you might not have the balance you thought you did there. Try to track spending more to determine if there is an issue. While the card isn’t quite positive, it is not a terrible card either. It is easy enough to compare how much you are earning with how much you are spending. It might be that you will have to take a closer look at the numbers and make some adjustments accordingly. Now is a good time to check how you are holding to your budget and if anything is going unaccounted for in your spending.',
  },
  'cups-3': {
    astrology: '',
    yes_no: 'yes',
    upright_general: 'The meaning behind the Three of Cups represents a period of happiness. You will be able to forget the worries of your daily life and spend quality time with family and friends.',
    reversed_general: '',
    upright_love_en: 'The 3 of Cups tarot love meaning signals celebrations, friendships, and gatherings. If you’re single, you may have luck finding love in your social life. A close friendship may also turn into romance. If you’re already in a relationship, social gatherings will bring the two of you closer together. When you go into the world together as a couple, it may make it easier to see just how well the two of you get along together. Being around friends and family can have a strong effect on the two of you, reminding you of why it is you two have chosen each other. Your love can feel deep and gratifying now.',
    reversed_love_en: 'Should you be single, the 3 of Cups tarot love meaning indicates that your romantic life may be fun and exciting, but perhaps short lived. Relationships started at this time can quickly fizzle once the two of you get to know one another better. If you’re already in a relationship, be wary of any third party that is trying to do harm to your partnership. Sometimes, this can come in the form of nasty gossip, or perhaps someone attempting to insert themselves between the two of you.',
    upright_career_en: 'The three of cups signifies celebrations in all aspects of your life. If it appears to relate to your career, it may be that a number of work-related events are on the horizon. These parties will be joyous occasions. These can take many forms. You may be celebrating a graduation, a change in position or a promotion. If you are launching a business and planning a release, these events are likely to go particularly well. Outside of these engagements, your office environment can be very positive right now. You might find that group work and collaboration is easier now that it has been in the past. It is a good time to enjoy these celebrations and supportive relationships.',
    reversed_career_en: 'When reversed, the events and celebrations that the three of cups normally represents may not go as planned. If you were planning a launch or other event, it might happen but will not bring the success and result you intended. Sometimes, this card can signal that these events will be delayed or canceled. If none of these situations apply to you, it may be likely that your work environment can be particularly toxic right now. There is likely gossip and other forms of undercutting that are destroying the camaraderie. There may be conflicts all around; some of this may be directed at you, but you may also simply have to deal with being caught in between the crossfire. Try your best to not be a part of this negativity. Do not add fuel to the fire as it will only burn you in the long run.',
    upright_finance_en: 'If you find the three of cups in a financial tarot reading, it might signify that you may have a lot to celebrate financially. All of this can be very exciting, but it is important to not get too carried away. You may find that your social life is more important to you than ever during this time, and while you may be in the position to be generous, make sure that your good fortune lasts. Be joyous, but also responsible.',
    reversed_finance_en: 'The reversed three of cups can signal financial stress, usually in a social context. If you’ve been spending a lot on your social life, or some kind of event or party of some kind, you may need to rein in your budget. For example, if you’re planning a wedding or a birthday party, be wary of what the strain that it can cause on your financial situation. There may be more things to pay for than you had anticipated. The upright three of cups also indicates this concern a bit, but reversed, the warning is more severe. Be wary of spending and giving beyond your means. It is easy to get swept up in celebration, but it will not serve you well in the long-term to lose track of your financial progress this way.',
  },
  'cups-4': {
    astrology: '',
    yes_no: 'neutral',
    upright_general: 'The Four of Cups tend to appear when you are feeling discouraged and unmotivated. You may feel as if there is no solution or way forward in your situation. Life has become stagnant, and nothing seems to make you happy or passionate. You are feeling apathetic - regardless of what happens, whether the day is good or bad, none of it matters to you. The Four of Cups commands a self-evaluation of your attitude so that you can pull yourself out of this rut. The solution is likely right in front of you, the hand is offering you a way out, but you release yourself out of your mental stubbornness and deploy new approach.',
    reversed_general: '',
    upright_love_en: 'If you’re single, the 4 of Cups tarot love meaning suggests a time of feeling boredom or indifference regarding your love life. Sometimes, this can come naturally after a break up, but one must make sure that this doesn’t come from unconsciously attempting to protect yourself from possible pain and suffering that love has brought you in the past. Opportunities come when you are open to seeing them, and right now you can’t be bothered. Should you already be in a relationship, there can be a lack of interest and weariness in your relationship. Excitement has faded and you may feel more like roommates than lovers. Sometimes this requires only some exploration and willingness to experiment. Without some effort from both partners, the relationship may be nearing its end.',
    reversed_love_en: 'You may be exiting a time of withdrawal and contemplation with the reversed 4 of Cups tarot love meaning, and you may be becoming more active in your romantic life again, this time, with a better understanding and appreciation for what it brings you. If you are recovering from a breakup, you may be just starting to let go of past suffering, and the future seems full of promise. Be excited for what the future brings you. With a better understanding of what you want and who you are, the potential loves that you encounter now can be refreshingly different.',
    upright_career_en: 'If you see the four of cups in a tarot reading about your career, you may feel distracted and distant at work. It might be hard to focus on the tasks at hand or get excited about projects. This boredom can also be impacting your mood negatively. You might feel down on yourself and thus find it even harder to be productive. None of this is aided by the overwhelming stagnation you probably feel. This stagnation might be the root of the issue. It can be hard to focus if you feel you are going nowhere. It may be helpful to take some time to detangle this issue; looking inward and knowing what makes you feel so unhappy and doing something about this can help you make a change for the better.',
    reversed_career_en: 'When reversed, the four of cups can signal an end to the stagnation you’ve been experiencing at work lately. This change might be sudden. It could feel like a revelation of sorts or as if a fog has lifted. You might find that your creativity has suddenly returned. As a result, you will be about to move forward in your work projects using this new found sense of inspiration and creativity. If your new realizations about your career are telling you that you need to make a change, now would be the time to do so. While the changes might be fast, do not mistake it for luck. You will still need to harness your newfound energy. The universe won’t give you anything unless you take action, but opportunities you did not previously consider or notice can suddenly take the forefront in your career.',
    upright_finance_en: 'When it comes to your finances, the four of cups can signal that you may feel distracted. Are you so busy being jealous of what others have that you do not see what is in front of you? You may be constantly comparing your own situation with others, but this envy can be preventing you from appreciating what you already have. Being more grateful can also help you see better ways of bettering your financial situation, and be more comfortable when it comes to taking material risks. If you are so fixated on what you do not have, you may never notice the opportunities to actually achieve that which you envy. At times this card can also present as a general disillusionment with money, capitalism and financial systems in general.',
    reversed_finance_en: 'The reversed four of cups can signal a journey towards economic betterment and security. This is not only a result of your ability to control your finances but is symptomatic of your efforts to appreciate what you already have. While you might have previously been envious of others for their financial security, you may be taking steps to be more positive with your approach to finances. The universe will reward you as you focus your energy towards better financial habits. Save and spend as you need to without letting what others think or have distract you. Be prepared to work for the rewards that this card signals.',
  },
  'cups-5': {
    astrology: '',
    yes_no: 'no',
    upright_general: 'The Five of Cups symbolizes disappointment and the feelings that come when things go differently than you expected. You are feeling unhappy that a certain situation hasn’t really turned out the way you had hoped it would. Instead of moving towards a more positive perspective, this card seems to say that you are dwelling in the past, inducing feelings of self-pity and regret. The water which is actually spilled from the cups shows that you might have missed an opportunity. It also shows that the problem is mostly emotional and not material or financial.',
    reversed_general: '',
    upright_love_en: 'You may be going through a period of mourning right now; there is perhaps much to grieve over. You perhaps are going through a break up of some sort, or if not that, a time of tension and arguments with your partner. It is helpful however, to understand that not all is lost. The 5 of Cups tarot love meaning signals emotional loss, but also that you may be overlooking what is still salvageable, and what has survived. Oftentimes, these bring the seed of hope. Did an argument teach you about something in your relationship? Did it help foster communication that would have otherwise remained silent? Did the break up bring you freedom to explore your individuality beyond your past relationship? As much as there are things to mourn over, the 5 of Cups tarot love meaning also suggests that there are things to look forward to.',
    reversed_love_en: 'It is time to stop living in the past, when the reversed 5 of Cups appears in a love tarot reading. This really is the card of moving on, of letting go of past grief and suffering. If you’ve recently gone through a break up, this card can be a welcome sight to help motivate you to accept what has happened, and make peace with it. As this chapter closes in your life, you are making room for new love to appear, one where truly live in the present, and are not comparing current potential romances with your past. If you’re still healing, it’s only natural. Give yourself time, and be gentle; you will find happiness again. If you’re already in a relationship, you may have just gone through a tense period. Hopefully, you and your partner will have had all the discussions you needed in order to feel like you are both understood and heard. Try not to dwell on past hurts and resentments; look towards the future and what the two of you can change, instead of what you cannot.',
    upright_career_en: 'The five of cups signifies loss and grief. In the context of your career, this can take place in the form of a loss of a job, business, a coveted project, or partnership. Perhaps you are being forced to take a step backwards in your career. Or it may be that someone with whom you work might abandon the projects you shared, or you may choose to walk away instead. This may be a period of sadness and transformation. These changes are hard, but they offer a learning opportunity. There may be more to salvage than what you initially thought. Try to maintain positive relationships with old coworkers outside of the office. Stay connected to the best elements of what you lost.',
    reversed_career_en: 'The reversed five of cups is a sign of recovery. When it comes to your career, if you’ve recently suffered a setback like a loss of a job, a layoff, or had a business go underwater, the reversed five of cups suggests that you have what you need to in order to move past these terrible times. You are able to recoup some of your losses now. Healing is on the way; you may realize that despite the suffering that you experienced, these losses allowed you to find a position that was much better suited to you. It is also likely that the stress and pain you have been experiencing as a result of these troubles will start to weigh on you less heavily.',
    upright_finance_en: 'The five of cups in a financial tarot reading can signify a lack of resources. You might be suffering a substantial economic loss. There may be lots of stress at the moment, and you may have to make sure that you are not spending wastefully in order to build up your financial security once again. It is important now more than ever to remain positive about your situation. Luckily, this card generally always suggests that there are many things that you can still salvage about this situation, so look towards what you already have, as well as your skillset to see what you can use to make up for the loss.',
    reversed_finance_en: 'If you’ve recently experienced some financial loss or turmoil, the reversed five of cups can signify relief and an end to this period. You may be finding new paths to financial stability by overcoming the losses that you experienced. Maybe you salvaged the remainder of your resources to invest in something worthwhile, like a business or a side-gig that is helping you build your financial cushion. Be proud of what you have overcome.',
  },
  'cups-6': {
    astrology: '',
    yes_no: 'yes',
    upright_general: 'The Six of Cups upright generally represents generosity, naïve happiness, and childhood. It can stand for you wanting to return to a happier time, whether it was when you were a child, teenager, or young adult. Many times, these memories are things of the past, which reflect the aspects of ourselves that have vanished. You may feel that remembering these times is the only way to feel happy. The Six of Cups appearing in a reading seems to indicate that while we may look upon the past with a happy eye, we must avoid living in it.',
    reversed_general: '',
    upright_love_en: 'The past comes alive again with the 6 of Cups tarot love meaning. This card can signal a revival of the past and the nostalgia that comes with it; you may be exploring happy memories, you may be more appreciative your partner’s sense of familiarity, or an ex can even reappear in your life again. The 6 of Cups can also represent a time of healing after wounds, and comfort may be important to you now. If you and your partner have had a stressful period in your relationship, looking backwards at the great times you spent together, and perhaps reliving them, can bring you great comfort. Beware however, of living only in the past. Let the past nourish your future; they are lessons to show you what you want to remain in your life, and what you wouldn’t.',
    reversed_love_en: 'With the reversed 6 of Cups tarot love meaning, you may be living in the past instead of the present. It is likely that a past relationship has been limiting you from opening yourself to love and making room in your heart for someone else. You may believe that you will never meet someone like your ex again, or that the love you once had was something of legend. It can be rather unfair for current or potential partners to be with someone who lives this way. Exes are exes for a reason; you may be only seeing the happy memories, and not the tumultuous ones. Let the past go. Otherwise you may be blocking out all possibility of love again, and you may never know whether the love that you are meant have was even greater than the one you lost.',
    upright_career_en: 'The six of cups often represents childhood, memories, and healing. When it comes to your career, now may be a good time to look backwards on the path that got you here. This card can be a signal that your past work can hold great lessons you need to learn for building your future. Think back on what you did right, as well as ensure that you aren’t repeating mistakes from your past. Alternatively, this card can signal that you may be reconsidering your career path, and perhaps returning to a position that you had once left.',
    reversed_career_en: 'The reversed six of cups can suggest that your work has become stale, and that progress in your career has perhaps stalled. You may be so frustrated from this stifling atmosphere that you are in the process of searching for a more exciting position or field of employment. There can be the desire to leave the security and comfort of your current position. Alternatively, you may be choosing to remain in the comfort of your current position to avoid the risks of searching elsewhere. In general, there is an important lesson that needs to be learned when this card is in reverse. Beware of repeating any negative patterns that may have followed you in your past workplaces; regardless of where you go, your own behavior often can recreate the same problems again if it is not dealt with.',
    upright_finance_en: 'The goodwill of the six of cups can relate to your finances in a number of ways. At times, this card can signify a gift or donation, or simply a sharing of resources. This card is also related to childhood and home, signifying that this sharing may come from family members. You may be returning to your parental home, giving you the ability to save your own funds more, while being amongst the comfort of those that love you. Alternatively, you may be on the other side of this, and welcoming family back into your own home, while sharing resources.',
    reversed_finance_en: 'Upright, this card is a sign of childhood and past memories. When reversed, the six of cups signifies that you are ready to set out on your own. This card is common for people who live at home but are ready to move out. It symbolizes that you are becoming financially mature. If you’ve been living with parents or others, you have better learned how to save and manage your funds, and you now have the discipline to make a life for yourself. These changes can be scary but necessary; enjoy the freedom that this brings you!',
  },
  'cups-7': {
    astrology: '',
    yes_no: 'neutral',
    upright_general: 'To draw the Seven of Cups in a reading shows that you need to clearly see the shadows and visions in your imagination, not only in your dreams but also in the real world. You should be careful of wishful thinking and be alert of the choices that you make. In one sense, the Seven of Cups indicates that you are a dreamer who is both excited and afraid of the things that you see in your unconscious. In another, the Seven of Cups is a reminder that although it is good to have dreams and wishes, it is even better to take action attaining those dreams. At one point in life, you will need to stop fantasizing and face the reality of life.If you are unable to make a decision due to the many options that are available, you should evaluate the advantages and disadvantages of each option so as to make the best choice. It is important to exercise caution when you are making your decision, as the card itself seems to show there is not only wonders and treasures that are available to you, but also monsters and shadows.',
    reversed_general: '',
    upright_love_en: 'Several decisions lie ahead of you with the appearance of the 7 of Cups in a love tarot reading. If you are single, you may have to make a decision between different lovers, or perhaps between love and family, or love and career. The 7 of Cups tarot love meaning can also signal that all the choices may look tempting right now, but though they glisten with promise, they may be illusions. Take your time and consider things carefully; only diligent communication and evaluation will give you what you desire. With love, we may be tempted to rush into a situation, letting lust and infatuation guide us towards something that in the long run won’t last. It is important to think of all the options, as well as look into any red flags or gut feelings of “something is wrong”, you may feel about the relationship. Trust your instincts.',
    reversed_love_en: 'Your lack of clarity about what you want in love can make your love life even more confusing and chaotic than it needs to be. There can be wasted time, missed opportunities, emotional upheavals, all because one is unable to make a choice. Your dating life can be filled with dead ends, broken hearts, and mixed messages. It is important to remain focused on what you want, instead of letting the world make your choices for you. Alternatively, if you are developing some awareness of what is important to you, taking action on those decisions can be rewarded. You can now take the steps you need to make things happen.',
    upright_career_en: 'The seven of cups depicts a person confronted by a variety of options. If this card appears in relation to your career, you may be presented with many different ways you can advance at work. This plurality of options is generally a good thing, but it may be important to be wary about how much time you spend dreaming about something instead of taking steps to make it happen. Remember, a potential path is only as good as the steps you are willing to take down it. You have plenty of ways to make progress in your career, and they can all serve you well. But none will get you what you desire if you don’t choose one path and commit to it. Whatever you end up deciding will serve you well; so, act decisively and with confidence.',
    reversed_career_en: 'While the upright seven of cups represents a plethora of options, the reversed seven can signify the opposite. It often appears to people who feel as if they are stuck in their job with no opportunities to advance. It is also common for those who feel as if they realized too late that the perfect position was available to them but they failed to act in time. Regardless of if either (or both) applies to you, try not to get hung up on these negative emotions. This card also represents a clear vision in terms of your career goals. Use these skills to honestly assess your position and where you have fallen short. Ask yourself what you could be doing to more proactively make progress in your career.',
    upright_finance_en: 'The seven of cups suggests that there are a number of ways you can better your financial standing. Take time to consider what your options are. Though generally this card does present you with many opportunities, it doesn’t mean that everything is decided for you. In order to turn these opportunities into reality, you will need to be proactive. Weigh each option and consider it critically. Often things that sound too good to be true are. Listen to your instincts and open your eyes to any red flags.',
    reversed_finance_en: 'When it comes to your finances, the reversed seven of cups can have several conflicting meanings. You’ll need to take a closer look at your circumstances to understand which apply to you. It can signify clarity when it comes to making financial choices, giving you the focus and willpower to reach your goals. You are not easily distracted and are thus able to focus on what you need. This foresight will serve you well as it prevents needless spending. You might find that you are able to make and follow budgets or other structured plans particularly well right now. Alternatively, this card can also signify confusion and delusions, or an inability to turn daydreams to reality. When it comes to opportunities that are being offered to you, ensure you are not being scammed. Make sure you understand all the facts of any deal that is being presented to you.',
  },
  'cups-8': {
    astrology: '',
    yes_no: 'neutral',
    upright_general: 'The Eight of Cups signifies time for change or transition, by means of walking away from something. Just like a caterpillar has to die before transforming into a beautiful butterfly, we all need to transform ourselves in our lives from time to time. This is the case especially after being tired of living what was the day to day, and embarking on a journey that will help one have a deeper understanding about life in general.Getting the upright side of this card shows that you are dissatisfied with your life and need to experience a higher purpose in life. You may have been exploring your options, flitting about from one choice to another, tasting the wine in each cup, as a means to sort out what it is that you really want with your life. You are now experiencing a feeling of exhaustion - and are coming to a realization that you must step away from what is familiar. It is a choice, and a recognition that true happiness will not be found in what you have already created.',
    reversed_general: '',
    upright_love_en: 'Take some time to ask yourself whether your relationship is one that you are happy with. The 8 of Cups tarot love meaning indicates that there is often some soul-searching that needs to be done about whether your partnership is one that truly fulfills you. Can you imagine spending the rest of your life with this person? Do they encourage you to be your best self? Do they encourage you to grow? Or instead are you with them because you are scared of being alone, or going back into the dating scene again? This is unfair for both you and your partner. It takes a lot of courage to look honestly within and answer these questions, as well as to walk away from a life that the two of you have built together.',
    reversed_love_en: 'With the reversed 8 of Cups tarot love meaning, your gut may be telling you that you need to leave your partnership, but there is something that holds you back. It is important to engage this and question that fear. It is so very difficult to give up what has been built, the time and emotions and energy that we have invested into another person, but sometimes one must be wise enough to leave something that truly isn’t working behind. You’ll have to work out whether the desire to leave comes from the relationship truly reaching its end, or whether it is still salvageable. Give yourself time to get a clear head about what you need to do, and address whatever it is that prevents you from moving on.',
    upright_career_en: 'The eight of cups in a career tarot reading can signal several things. Since the card in a general sense signals walking away and leaving something behind, it could be as simple as you taking a vacation from work, or as stressful as walking away from an unfulfilling job. If work has been especially draining recently, just a little escapism might help you feel refreshed. If you’re trying to make the decision about whether or not to leave your job, remember that sometimes you have to know when to cut your losses and move on. If you know how to make the most of any situation and make responsible decisions, it will offer you an exit to bad situations in favor of better ones.',
    reversed_career_en: 'When the eight of cups is reversed, you may be finding it difficult, or even downright refusing to do walk away from something out of fear. You may feel that you are in an unfulfilling career, which you have the power to change. You can choose to either accept a role that offers you no emotional reward, creative outlet, or opportunity for growth, or make the necessary changes to look elsewhere. Do not be afraid of leaving something behind if it is no longer serving you. This task is true for those who own their own business as well. If you are holding on to your business or job out of a sense of duty or fear, now is the time to let go.',
    upright_finance_en: 'Sometimes in order to make the right choices for us, we need to leave what we built behind. The eight of cups can suggest that you may have to leave behind some of your financial security in order to build a life that is right for you. Take this as a chance to attend to your finances before you make the big decision. Pay attention to how much you spend and on what. Be cautious of big expenditures at the current moment. You might find that you do not have as much funds to spend on them as you think you do. This card may just be a warning to plan ahead.',
    reversed_finance_en: 'The reversed eight of cups signals that you may find it difficult to leave behind some of your financial security in pursuit of something better for you. You may be holding onto a job that does not serve you out of fear that you won’t find a better paying job elsewhere. This concern is valid, but bold decisions and risks are sometimes required. You’ll need to consider how much your happiness is truly worth. Set aside a little bit of time each day to look for openings that might meet your economic needs while also serving your emotional ones.',
  },
  'cups-9': {
    astrology: '',
    yes_no: 'yes',
    upright_general: 'After a long journey, the Nine of Cups symbolizes the finding of self-satisfaction. The emotional journey of the cups is starting to come to a close after the volatile ups and downs you faced in the earlier numbers of this suit. You have struggled to find purpose and joy after loss, you have tasted the different things that life offers, and you have left comfort in order to find greater heights. Here, you have found them, and you are indulging yourself as you celebrate this new stage of your life.',
    reversed_general: '',
    upright_love_en: 'Appreciate what you have when the 9 of Cups appears in a love tarot reading. Wishes here are meant to come true, and it is best to look forwards to the future with gratitude. There is much to celebrate, and if you’re single, love can be found at parties and other happy gatherings. Go and enjoy yourself; now is not the time to be calculating or strategizing about your goals, but instead simply have fun. Lightheartedness can draw others to you. If you’re in a relationship, you’ll find that your love life will feel more cheerful and sweet. This can be a great moment to feel closer with your partner.',
    reversed_love_en: 'With the reversed 9 of Cups tarot love meaning, you may find that you your relationship ticks all the boxes, and looks great on paper, but it still feels as though something is missing. Perhaps you and your partner haven’t been as close as you would have wished; maybe there is a lack of a deeper connection. There’s no reason to fret, as this can be solved with earnest and intimate conversation. On the other hand, you may have been so wrapped up in getting into a relationship, that you haven’t noticed that it was you that needed to grow. Sometimes, we can get into a romance in order to distract us from the inner work that we must do in order to be happy. Without doing that inner work, regardless of the wonderful romances that come our way, that dissatisfaction will always stay.',
    upright_career_en: 'When it comes to your career, the nine of cups signifies that you may be able to find respect and recognition in your field. Whatever projects you start now may be easy to finish, and the skill you demonstrate in completing them can also earn you much praise. If you’re looking to advance in your career, this can be an excellent time to ask for a raise or promotion. People will likely be more receptive to these requests now than in the past or, potentially, in the future. Take advantage of this moment. Overconfidence is never wise, but do not be shy or bashful now. You have worked hard for this recognition.',
    reversed_career_en: 'The reversed nine of cups can be an upsetting card for your career. As the upright card is considered the “wish card” of the tarot, in reverse, it can signify that something you’ve always dreamed of is quickly not turning out like how you imagined. You might have hoped that by opening a business or starting this new job that everything would be better, when the reality is as far from this as you could imagine. You may find that the work is harder, more tedious, or simply too much to handle. There may also be a lack of rewards, you may not be recognized for your efforts. Instead of feeling overjoyed about your new career path, you may instead feel disillusioned and disappointed. You may need to go back to the drawing board to make some changes.',
    upright_finance_en: 'The nine of cups signifies wishes granted, and when it comes to your finances, this card can suggest that you have everything that you need. This card signals fortune, feeling content and financial security. If you’ve been working hard, you’ll find that you can be generously rewarded. Take the time to enjoy this moment; you have earned it.',
    reversed_finance_en: 'When it comes to your financial situation, the reversed nine of cups can signal that your expectations were not met. Sometimes this can signal that something you’ve put your money towards did not turn out as hoped. If you made any big purchases, invested in something, or used that money to help a family member, the results weren’t quite what you had thought they would be. Alternatively, the reversed nine of cups might signal that your hopes for financial stability may not have yet happened. Be patient. Remember that you will have to earn those dreams. Focus on what you do have and how you can better work towards your goals.',
  },
  'cups-10': {
    astrology: '',
    yes_no: 'yes',
    upright_general: 'From its joyful depiction, we can assume that the Ten of Cups embody happiness, joy, contentment and emotional satisfaction in your family, relationship or companion. It represents an idyllic state of comfort, harmony, peace and love which makes you feel like you are in paradise. This is where all your dreams, wants, needs and wishes have been fulfilled, and you feel a complete sense of satisfaction. Take a moment and breathe, look around you and be thankful for all your blessings. This card signifies something that so many of us are searching for.',
    reversed_general: '',
    upright_love_en: 'Love is calm and sweet with the 10 of Cups tarot love meaning. Spending time with your family can be particularly rewarding right now. You may be introducing your partner to your family, or taking the next step in your commitment together. The 10 of Cups tarot love meaning also suggests long term stability, tranquility and comfort. If you’re single, and you meet someone at this time, it’s likely that the relationship will be one that lasts.',
    reversed_love_en: 'Clashes between family and love can be suggested by the 10 of Cups tarot love meaning. External matters may be creating chaos in your romantic life, including meddling relatives that believe you are not meant to be together. It is important now more than ever to face criticisms from family as a unit; defend each other and avoid public arguments. Ensure that your partner feels loved even during this turbulent time.',
    upright_career_en: 'Though the ten of cups is often more connected to family than work, this card can also bring some joy to your career. This card can signify a kind of comfort and belonging that you find from your current position. There is enough opportunity for growth and creativity that you do not need to worry about these aspects of your career. There is also likely cohesion and happiness between you and your coworkers, and the office culture can feel welcoming and supportive. You may find that the job gives you a comfortable work-life balance as well, and you have the security of spending a good chunk of time with your family. The card can also signify retirement or leaving a job to take care of a family.',
    reversed_career_en: 'When the ten of cups is reversed in a career reading, you may be dealing with a feeling of tension, loneliness and frustration at work. The atmosphere is more hostile than usual, and your colleagues may not be supportive right now. You may be left with the feeling that you don’t quite belong in this position, and your basic sense of stability and security may feel shaken. Sometimes, this card can also signal an upset to your work-life balance. You may be working more hours than you expected and your family life is suffering as a result.',
    upright_finance_en: 'Since the ten of cups signals family stability and harmony, you may find that you and your loved ones have what you need to feel happy and comfortable. This doesn’t always translate to wealth, but the knowledge that there is enough for a feeling of stability and security. If you’ve previously had fights with family over financial issues, these may now dissipate.',
    reversed_finance_en: 'When it comes to your finances, the reversed ten of cups can signal domestic disharmony regarding issues of money. You may be faced with disputes at home about how much you should be spending, or how much of what you have is yours versus someone else\'s. There can be a basic feeling of financial instability at home that can add to this nervous atmosphere. Your finances and your emotions are likely to be deeply connected right now, and resolving issues in one or the other may be helpful in clearing out the whole mess.',
  },
  'cups-11': {
    astrology: '',
    yes_no: 'yes',
    upright_general: 'One of the most important meanings within the Page of Cups is that you should be open to new ideas, especially ones that stem from intuitive inspiration. The card seems to state that such inspiration should be embraced, despite it being something that you may not expect. It could lead you to adventure and open many doors. If it is a calling of a creative nature, for example, one to get into music or art, there\'s an especially strong push from this card to go for it. When you are being faced by difficult situations, and you have stopped chasing your dreams, the Page of Cups seems to say that you that you should tackle the issue from a totally different perspective. It symbolizes persistence as this is the only way that you can make your dreams come true. Listen to your intuition, follow your calling, and believe everything is possible.',
    reversed_general: '',
    upright_love_en: 'The person represented by the Page of Cups tarot love meaning is someone who is intuitive, creative and emotional. They can often have an innocent and naive quality, regardless of their actual age. If this card doesn’t point to a person in your life right now, happy surprises could be in store for you. If you’re already in a relationship, you may be looking at it with fresh eyes, a sense of wonder and awe, and a newfound appreciation for the parts of your partner that you haven’t seen before. If you’re single, your approach to love can be one of childlike fascination. Everything about romance and potential partners can feel delightfully novel to you.',
    reversed_love_en: 'Shy, hesitant and maybe a little awkward, the Page of Cups tarot love meaning can point to someone in your romantic life with these characteristics. They may react well to some much needed kindness, slowly opening up to you if they feel safe. Sometimes however, this person may also be a bit emotionally immature; there could be temper tantrums, insecurity, and lots of nonsense. Should this card not represent a person, be aware of these traits in yourself. Have your insecurities gotten the best of you? How have they affected your romantic life?',
    upright_career_en: 'The page of cups is an imaginative, sensitive and creative person, and in a career reading, they can often signal a focus on creative fields like art, fashion, poetry and music, or any field in which they can use their innate talent to create something. The page of cups can often have trouble putting their feelings into words, and thus, their creative outlets tend to be places where they can express themselves. They often have their head in the clouds however, so ensure that you are not simply daydreaming about your work goals, and are actually putting effort and taking action to make them become real. Follow your dreams, but make sure that they are well grounded in reality first.',
    reversed_career_en: 'Have you had issues dealing with your feelings at work? The page of cups can indicate that you have been unprofessional, or perhaps letting your emotions get the best of you. Oftentimes, when we are in new situations we may be faced with feelings that we don’t know how to channel into something positive. If your line of work is in a creative field, the reversed page of cups can also suggest that you’ve had a hard time dealing with creative blocks. This will pass too, if you can remember the reason you fell in love with doing what you did in the first place. Find inspiration.',
    upright_finance_en: 'When it comes to finances, the page of cups can suggest daydreaming, and perhaps financial goals that are unrealistic. It may be better for your long term future to focus on things that are achievable, and completing goals one at a time instead of hoping for the lottery, or another risky investment to bring you what you desire.',
    reversed_finance_en: 'If you’ve been dealing with any financial setbacks, you’ll need to make sure that you have your emotions under control. Avoid letting yourself get carried away, and make any risky choices as a result. If you’ve been in denial about your financial state, now is the time to face it instead of running away. Many valuable lessons can be learned; and denial is only delaying the inevitable.',
  },
  'cups-12': {
    astrology: '',
    yes_no: 'yes',
    upright_general: 'The truth is that the Knight of Cups is the most feminine amongst all the Knight cards in the tarot. It\'s important to note though, that this doesn’t even slightly suggest that he is any less of a worthy knight. It implies that he is in proper touch with his emotions and his intuition, and that he uses them for his own well-being and during his many romance and seduction quests. He is usually quite attractive and charming to others, regardless of their gender. When faced with an actual decision, the Knight of Cups is going to listen to his heart, regardless of whether this is actually a logical choice or not. He can also manifest as an event or a person in your life, or a part of your own self. He appears as a messenger – and with him, he carries an invitation or an arrival of something or someone which is going to have a certain emotional benefit for you. As a knight, he is also charged with taking the gifts of his suit, and bringing it outward into the world. He therefore can also represent the undertaking of some project with significant emotional or creative value for you.',
    reversed_general: '',
    upright_love_en: 'Romance is coming your way with the Knight of Cups tarot love meaning. This person is very much in love with the idea of of love, and goes out of their way to show it. Sometimes though, this person goes a bit too far in their pursuit of true love; so much so that they have rather unrealistic expectations of perfect partners and perfect relationships. Without a gentle dose of reality, they can go from lover to lover, leaving a string of broken hearts simply because each finally showed their very human flaws. Be aware of approaching your romances with this attitude. Try and enjoy things in the moment, and keep the real world in sight as you go on your quest for love.',
    reversed_love_en: 'When the Knight of Cups is reversed, he can be rather passive aggressive, and full of empty promises. Being a great romantic, many of his tales and his proclamations of love can be over exaggerated. If this doesn’t sound like a person in your love life right now, it can instead point to feeling overwhelmed with the emotional changes that are occurring in your romantic life. Feelings can run hot and then cold, and perfect appearances can be quickly shattered. Be wary of lovers that whisper sweet nothings, and make sure that they truly mean what they say.',
    upright_career_en: 'The knight of cups represents your ability to handle situations at work with tact and grace. You are particularly diplomatic right now. Conflicts around you can be easier to deal with at this time. You are able to resolve issues with creative solutions, as well as your emotional connection and awareness of others. You can see solutions that might otherwise remain undiscovered. This creativity can apply to you and your intended profession in general. If you have been considering entering a job in a creative industry, this card can also signify your success in that field.',
    reversed_career_en: 'When It comes to your career, the reversed knight of cups can have numerous interpretations based on the context and other cards in the spread. Your office environment may be rife with disagreements right now, and everyone may be on edge. You may also want to consider how you are handling your emotions at work right now; is your moodiness contributing to this environment? Alternatively, it may be that your desire to maintain the peace is getting to self-destructive levels. Instead of dealing with your problems, you may be doing whatever you can to avoid confrontations, even if it can be helpful to express these frustrations. Try and strike a balance between being so diplomatic that you take on everyone else’s problems, versus lashing out when it is inappropriate.',
    upright_finance_en: 'When it comes to your finances, your empathy, compassion and skill in mediating tough conversations can be helpful right now. Disputes about money are likely to be eased so long as you can use this talent to keep the peace. If you’ve been in a strained financial situation, this card can also suggest that you may need to get creative in order to solve your issues. It is likely, however, that you will succeed in turning your problems around once you are able to look outside the box.',
    reversed_finance_en: 'The reversed knight of cups can be a passive bystander in his own life; and in financial contexts, it may be that you are not acting decisively. At times, this card can also suggest that what you hoped for hasn’t quite turned out as planned. You may have quickly put all your eggs in one basket, only to be disappointed at the outcome. Make sure you do your research about any large purchases or investments before making a decision.',
  },
  'cups-13': {
    astrology: '',
    yes_no: 'yes',
    upright_general: 'We can understand the meaning of the Queen of Cups from taking a closer look at the woman in image. She is seen as compassionate, caring, sensitive, and nurturing. She connects with people on the emotional level, so people enjoy her honesty and fairness. The appearance of the Queen of Cups in a reading can be guiding you to find help from others. Most times, like the other queens, this is a female figure that will come into your life. The Queen of Cups has an intuition which is very powerful, and is only rivaled by the one of the High Priestess. The Queen of Cups acts as a mirror and reflects the depths present in others, so they see themselves in a new light. Most times, the Queen of Cups can also represent the trusted inner voice you have within you. She seems to say that you should take the time to focus on your emotional health before trying to help others. Self-love creates compassion.',
    reversed_general: '',
    upright_love_en: 'With her wise, supportive and kind nature, the Queen of Cups is likely to have many admirers. Her compassion makes it quite natural for her to lend an ear to anyone who needs a listener or a shoulder to cry on. If there is nobody entering your life now with these traits, you may find that it is you taking on this role. You may attract many people this way, but be careful avoid someone clingy and too dependent on you. It is important to be able to draw boundaries at this time, as emotional support is also emotional labor. Don’t wear yourself out. Let your intuition guide you. Those in relationships can enjoy deeper love at the moment.',
    reversed_love_en: 'Do you find yourself always taking the role of caregiver and supporter in your relationship? The reversed Queen of Cups tarot love meaning can signal that you’re putting much more effort into the relationship than your partner. You may even occasionally feel more like a parent than a lover. The balance between the two of you must be corrected. Alternatively, you may find the emotional environment to be rather turbulent and constantly shifting. You or your partner may feel as though you are walking on eggshells, never knowing when the next argument will arise.',
    upright_career_en: 'The queen of cups is a particularly caring and compassionate card. Thus, if she appears in relation to your career, you can consider several meanings. This queen can serve as a reminder that whatever you are doing should help you feel fulfilled emotionally and not just financially. When it comes to your workplace environment, this card can point to someone that takes on the caring and compassionate role amongst your colleagues. Sometimes, this card can also signal that you are taking this role. Along this vein, the queen also hints that the guidance of a person with this nature in your field could benefit you.',
    reversed_career_en: 'When the queen of cups is reversed and appears in the context of your career, you may be dealing with some emotional issues at work. You may find that the projects you’re working on, or the environment you’re in is emotionally draining right now. Sometimes, the exhaustion that we feel comes from our own needs being unmet. Since the queen of cups can be so focused on the needs of others, it may be difficult for her to put her needs as a priority. Have you been so focused on making your colleagues, clients or your boss happy that you have neglected doing what makes you happy? Take the time to take care of your own emotional health for now.',
    upright_finance_en: 'You may be using your financial resources to care for others at this time. The queen of cups can signal that your heart moves you to contribute to a cause, a family member or a friend that is in need. Often when the queen appears here, it is to remind you that money isn’t everything. You should not focus on it at the expense of other considerations in your life.',
    reversed_finance_en: 'When it comes to your financial situation, the reversed queen of cups can be a card to look towards your own emotional well-being and its relationship to your sense of financial security. If you’ve been spending compulsively, or indulging in a little retail therapy, this can be helpful in the short-term, as long as you are also addressing the root cause of your unhappiness. Beware too of overstretching yourself; your considerate and loving nature can mean that it’s easy for you to take care of others, even when you are low on resources yourself.',
  },
  'cups-14': {
    astrology: '',
    yes_no: 'yes',
    upright_general: 'The King of Cups is one of the most influential cards in the suit of Cups. He represents creativity, emotion, and the unconscious. The card shows the ability to restrain one\'s emotions and be fully in charge of your feelings and impulses. Therefore, the King of Cups represents a balance between the intellect and emotions. He indicates that there is a strong relationship between understanding and feeling.',
    reversed_general: '',
    upright_love_en: 'A balance between the heart and the head is represented by the King of Cups tarot love meaning. This person is emotionally mature, and values family. When emotional tensions are high, their calm and collected responses are just what everyone needs to maintain peace. When this card isn’t represented by a person in your life, it can be a suggestion to use both logic and intuition in your approach to love. Approach romance with practicality, but also with wisdom, compassion and understanding. Combined, the love you find is sure to be deep and rewarding.',
    reversed_love_en: 'This king lacks consistency, empathy, or morals. In love, he can be rather manipulative and selfish, using his emotional intelligence for his own desires. If this doesn’t represent a person, you may have to deal with a love interest leading you on, or using you. Alternatively, the King of Cups tarot love meaning can simply suggest some kind of selfishness in your romantic life. You or your partner may not be putting effort into your relationship, content to let your partner do much of the work.',
    upright_career_en: 'At times, the king of cups can signify a more experienced, caring and compassionate advisor or mentor who can help you develop an emotionally fulfilling career. This card is also about balancing one’s emotional needs and practical, logical needs. Your wisdom and ability to balance your head and your heart can win you the respect and admiration of those around you, and can make you especially valuable when it comes to ironing out conflicts between various parties in the office.',
    reversed_career_en: 'The reversed king of cups can signify dealing with a boss or a manager who has become a bit of a tyrant. While the upright version of this card is compassionate and emotionally aware of how others are doing, this reversed king can be selfish, and ignorant of everyone’s needs except their own. Insecurity and lack of emotional control can play a big factor in how this person handles their work environment. At times, this person can also be you. Sometimes, this card can indicate that you are at your position solely for the money, and you may be feeling unfulfilled. Even if you began at this position with excitement and passion, it may be slowly disappearing. Try and see whether you can reconnect with what you enjoyed about this job in the first place.',
    upright_finance_en: 'On one hand, the king of cups signals some level of financial stability. This stability is the result of your judicious nature when it comes to making decisions. If you find yourself in the midst of making some large purchases or investments, this card can be a reminder that you should be both cautious and logical, as well as satisfying an emotional need.',
    reversed_finance_en: 'While the upright king of cups is a sign of good judgment, the reversed king is a sign of the opposite. You may find it difficult to control your spending, or make logical and well-informed decisions. You may be letting your uncontrolled emotions make your financial choices for you, and when unchecked, can create problems for you.',
  },
  'wands-1': {
    astrology: '',
    yes_no: 'yes',
    upright_general: 'Wands symbolize creativity, and the Ace of Wands is the boldest among the cards in the suit. It is not the kind of creativity that you learn from school or as a hobby. It is bravely finding your own voice, it creates a place where you can develop your own vision. In other words, it is associated with willpower, and creativity in the cosmic sense.When you draw the Ace of Wands, it is an indicator that you should just go for it. Take the chance and pursue an idea that you have in mind. Take the first steps to start the creative project. The Ace of Wands calls out to you to follow your instincts. If you think that the project that you\'ve been dreaming of is a good idea, and then just go ahead and do it.',
    reversed_general: 'The reversed Ace of Wands indicates trials and tribulations that you will face in the near future. You might not have any direction, which leads to being uninspired or unmotivated. At this point of your life, you might not know what you really want to do. You don’t know how to get out of the slump. In the case that you already have a goal, you are not excited to achieve it. When you draw a reversed Ace of Wands, you should consider taking some time off to allow inspiration to come to you. You feel weighed down by your current commitments and responsibilities that you can’t come up with new ideas, or muster the passion to push forward in your projects.The Ace of Wands reversal meaning can also indicate delays with your current projects. You want to finish your tasks, but there are things that get in your way. Or you have an idea but don’t know how to execute it and make it a reality. When this is the case, you should be patient and wait for the right time.',
    upright_love_en: 'The Ace of Wands tarot love meaning signals excitement and passion; things are heating up for you! Your relationship may take on a very sensual character at this moment, and the same holds true of potential romances if you’re single. There may be lots of flirtation and attraction, and even some room for longer lasting relationships should the lust also be accompanied by some kind of spiritual understanding. If you’re committed, and the passion has since faded, now can be the time when it is revived again. There is a good chance for rekindling the flames, and for the two of you to feel more emotionally connected.',
    reversed_love_en: 'When reversed, the Ace of Wands tarot love meaning heralds intense passion, but one that may quickly burn out. There can be lots of excitement in the beginning stages, only to fizzle out when commitment is mentioned. Long term romances may not be favored by this card. If you’re in a relationship, this card can suggest that at this moment, your enthusiasm for your each other may not be very high. Sometimes, it’s simply a matter of learning to communicate better, or making sure you dedicate some time for one another. Effort is required to ignite passions once more.',
    upright_career_en: 'If you find the ace of wands here, you are likely in a time of high growth for your career. It is a moment in which your preparation is meeting opportunities. You might also find that your work is particularly inspired right now. You can push past old boundaries and see potential in all experiences. This is a good moment to confront issues that hindered your progress in the past because you are now in a better position to confront them. Your creativity and problem-solving skills are at a high. Use this energy to the best of your abilities.',
    reversed_career_en: 'The reversed ace of wands means a lack of inspiration. This deficit can manifest in a variety of ways. You might have a hard time brainstorming right now. If your career requires a lot of creativity, it might seem like you are drained of ideas. When you sit to write even simple letters or papers, you might find yourself staring at a blank page for longer than usual. This lack of creativity makes it a difficult time to start new projects or jobs. This timing is particularly unfortunate because you are also prone to frustration at a lack of progress right now. Try to be patient with both your inspiration and your career path. There are lulls sometimes; this is nothing uncommon or inescapable. Treat yourself with kindness and do things that tend to inspire you when possible.',
    upright_finance_en: 'The upright ace can signal the end of economic struggles. Whatever strains existed before are beginning to dissipate. This might be because you are at the end of paying off debt. If you have not experienced stress from a specific source of debt, your finances might still improve in other ways. You might find yourself receiving a gift or bonus. Whatever you receive is likely to just push you past your previous concerns. This is a good card, but it is not a symbol of exorbitant wealth. Do not conflate this relief of pressure with an ability to spend recklessly. That decision is never wise. Instead, appreciate that you will have one less stressor in your life for a bit.',
    reversed_finance_en: 'The reversed ace of wands can suggest that your finances may be taking a turn for the worse right now. If you see the ace of wands in this position, start to prepare for a dip in your finances. Now is not a good time to invest in anything or make large purchases. You are likely to lose whatever you set aside. Be particularly cautious about gambling, buying stocks, or any practice that advertises high potential (and high risk). Instead, rely on previous preparations you may have made to weather bits of economic uncertainty. Try to prepare, as best you can, for the worst, but hope for the best.',
  },
  'wands-2': {
    astrology: '',
    yes_no: 'yes',
    upright_general: 'The Two of Wands is a more mature version of the ace of wands, meaning that that this tarot card is all about planning and moving forward – progression. Look at it this way; you have already set out to achieve a particular task, which means you have turned an idea into a realistic plan. Such a plan will require fulfillment and therefore you have to progress from just having the plan to actually achieving what you set out for.Discovery is being considered as another two of wands meaning. This is because it means that you are stepping out of your cocoon and exploring new experiences and worlds. While the beginning might seem tough and difficult, the Two of Wands card encourages you to strive on and push forward.',
    reversed_general: 'The Two of Wands reversed meaning suggests the need to set up long-term goals. Begin the process of setting up your goals by identifying what to you is important. Proceed by planning how you intend on achieving such goals. Another Two of Wands reversal meaning suggests that you have ignored important fine points associated with planning your future. Lack of proper planning could be the reason for your downfall. Other interpretations can include either overconfidence or lack of patience, both are possible in bringing you disarray in your path forward.',
    upright_love_en: 'What goals do you have when it comes to your romantic life right now? The 2 of Wands tarot love meaning can signal that you’re in the process of considering changes, and making the plans to do so. If you’re in a relationship, you have the chance right now to make adjustments. If you are considering taking your commitment to the next level, this card suggests great promise, so long as you do the work to envision exactly what you want, and put your thoughts into action. Communicate with your partner, and create a path together into the future that you both want. Decisions you make together now can have the profound ability to push the two of you closer together.',
    reversed_love_en: 'Sometimes, regardless of one’s plans for the future, things don’t fall into place. Now may not be the best time to push your romantic goals forward. Love takes time to happen, and you may have to be more patient than usual. It is best to use this time to really consider what it is you want from your love life, and figure out a clear path to achieve it. The 2 of Wands is a card of planning, setting expectations and charting a path forward, and the best laid plans are ones that start from a clear vision. The 2 of Wands love tarot meaning can also signal you may be experiencing some hesitancy when it comes to your romantic interests.',
    upright_career_en: 'When upright in the career position, the two of wands signifies that you are making plans for your future career. You may be taking a look at your ambitions and charting a path towards that dream. You can be considering the ideal company to work for, what your specialty may be, or laying down plans to start your own business. This can be an exciting time for you as your dreams are taking shape. Let these first steps be a strong motivation to continue down this path.',
    reversed_career_en: 'The two of wands, when reversed, can have two meanings. You may find that the plans that you laid out for your career path are not going the way that you envisioned. You may have missed details and had many obstacles that you did not foresee. These issues are creating trouble for you now. Alternatively, you may have made all the plans in the world; perhaps drawing out several scenarios and outlined all the risks. But fear may prevent you from taking your first steps. Instead of overanalyzing every single detail, it may be better for you to just take action. One cannot plan for everything; we have to trust in our own ability.',
    upright_finance_en: 'When it comes to your finances, the two of wands represents financial stability. This stability does not necessarily mean overflowing wealth but signifies that your situation is comfortable and steady. You may be comfortable enough to be making plans for your long term financial future. It is a good time to make conscious choices without fear of serious repercussions. If you have access to money, consider investing it in savings.',
    reversed_finance_en: 'A reversed two of wands here can signal financial instability. This does not mean huge losses or huge gains so much as general chaos in your bank accounts. Your plans for your financial future may not be panning out, and this can be a tumultuous time economically for you. Do not use this time to make investments or large purchases right now, but instead take a closer look at your numbers and what your long term goals are. Try and get more clarity.',
  },
  'wands-3': {
    astrology: '',
    yes_no: 'yes',
    upright_general: 'The meaning of the Three of Wands hints that you are planning or going to plan for the future with more conviction. This could mean that everything around your plans is going smoothly, as you have taken the time to plan your future, and are taking steps to turn plans into action. It hints that you are perhaps creating a stable foundation for yourself.The symbolism within the Three of Wands is that opportunities that can take place to widen your horizons in many areas. It also is a warning to keep your mind open as better opportunities could open up to you. As you take steps towards achieving what you set out to do, you are also becoming more aware of opportunities that are coming your way, and this could be take you out of your comfort zone. This pushes you to sometimes embrace change, and to start thinking in the long-term.',
    reversed_general: 'The reversed Three of Wands indicates that you may have been embarking on personal journeys or developments, but you have not received the achievements that you were hoping for. This could be due to delays or road blocks. Despite all this, the card reminds you that all of your work has not been for nothing, but rather that it has helped you with your personal strength and fortitude.The Three of Wands reversed can also mean you need to take some time to plan your future. This is especially true if you have not started on your long term goals or have become overwhelmed by the tasks that you face now, or will have to face soon. You are only reacting and not acting with thought and deliberation.However, the most common Three of Wands reversed meaning is a nudge to include planning for future changes, and to watch for better options in case that they show up. The figure on the Three of Wands knows this and always keeps his eyes open for how the future could change, and it is a worthy lesson to learn.',
    upright_love_en: 'With the 3 of Wands, it seems that your love life is heading to its next phase. Should you find yourself in a new relationship, it looks like you’ll have to make sure to create a strong foundation for lasting commitment. If you’re in a committed relationship, this can be a great moment to set sight of your goals as a couple, and work together to achieve those goals. Have that conversation of what it means to move in together; communication about even the most mundane details can ensure that you take this step with the least amount of frustration as possible. Alternatively, this card also can signal travel; take the chance to explore the world together - or if you’re single, new places can spark the love you’re looking for.',
    reversed_love_en: 'Sometimes you can\'t say or do the right thing; if this is the case it might seem easier to hide your head in the sand. This would be unwise; you really need to get any issues addressed and problems sorted now.The course of true love is seldom entirely smooth and any recent relationships may struggle to get off the ground, this doesn\'t mean they don\'t have wings, just that a bit of patience is called for. Trying to force things forward will be counterproductive. Before committing to a relationship, check your partner is all you think they are.In all relationships we have to compromise from time to time, demanding your partner changes to suit you can cause problems. Are you being realistic?',
    upright_career_en: 'When upright, the three of wands depicts adventure and new experiences in every aspect of our life. This is true in the career position as well. Right now, you are likely to experience new opportunities to explore your career. Beyond that, your career can push to make bold choices that you might otherwise be hesitant to make. Here, it signifies a new chance or daring opportunity. This could mean starting a job abroad or otherwise traveling for work when you would not normally feel inclined to do so. This also applies to business. If you own a business and have debated going global, now is a good time to do so.',
    reversed_career_en: 'Reversed, the three of wands can indicate frustration, stagnation or rejecting opportunities that are being presented to you. There may be many things that you wanted to explore, but you might feel boxed in or like you’ve let chances go by without capitalizing on them. Perhaps you turned down the chance to go somewhere else for a new job or expand your business globally. If you have not recently made such decisions, it could be that your frustration and annoyance with a lack of progression or challenge at your workplace is taking its toll.',
    upright_finance_en: 'The three of wands, when upright, signals a time when you can enjoy the profits of your hard work. Your hours of labor are being rewarded. Don’t be afraid to spend your hard-earned money on something that broadens your horizons such as a trip or extended journey. If you have been debating a class or trip but held off for financial reasons, the cards are telling you now is your chance to embrace these desires and expand your mind. Your ideas of what financial stability and your relationship to money may be expanding now as well.',
    reversed_finance_en: 'In this position and with this orientation, the three of wands signifies that you may be in a state of financial chaos. It might not be that you are lacking money, but there are delays in being able to achieve your financial goals. If this card appears to you here, take better stock of what funds you have coming in and how much of it is going out. You may be able to weather this period without economic loss if you are more diligent. Be aware of your finances and take charge of them.',
  },
  'wands-4': {
    astrology: '',
    yes_no: 'yes',
    upright_general: 'The overall meaning of the Four of Wands is that it heralds celebration as well as a harmonious, happy and relaxed home environment. In terms of numerology, the number four symbolizes stability as well as particularly reliable foundations. These are associated with a period of happiness and balance.The symbolism within the Four of Wands poses that this is the perfect time for you to get together with close people such as friends and family. This could be with or without any special occasion. Oftentimes the card is known to reflect a period of holidays when you are together with your friends and family for an extended period of time. It might also be suggesting for you to invite your closest friends for a great and intimate dinner and share a laugh or two.',
    reversed_general: 'If the upright position of the card reflects balance, stability, and harmony, the reversal position of Four of Wands implies that there is a breakdown or complete lack of harmony in your family or in your home. It’s highly likely that there is a lot of tension between the members of your family or other loved ones. If you have completed something that is important to you, you are expecting to share it with those that are closest to you, and to come home to a welcome celebration, but instead, you find a lack of support. This may leave you feeling rather uncertain when it comes to your own relationships as well as the things that you can and cannot depend on.',
    upright_love_en: 'This card is the card of family, of reunions and of festivities. The 4 of Wands tarot love meaning can bring about engagements, marriages, or other gatherings that commemorate you and your love. If you’re in a stable relationship built on a strong foundation of trust, support and understanding, your union may be strengthened even more with the support and witness of your family and friends. This kind of love is not just the love between two people, but a love that is supported within the context of a larger community. Should you be single, you may find love within these communities and gatherings.',
    reversed_love_en: 'There may be some conflicts occurring when it comes to family and your romantic life at the moment. The 4 of Wands tarot love meaning can signal incompatibilities between your larger community of friends and family, and your partner, or the way that you are approaching love and romance. Sometimes, since this card is also the card of deepening your commitments on a more public level, there can be some fear and hesitation about taking these next steps. Change, especially binding oneself with another person, can be wonderful and rewarding, as well as terrifying. These emotions can exist together, but only you will be able to know whether it comes from a deeper place than just cold feet.',
    upright_career_en: 'The upright four of wands is a stable and social card. It, when upright, signifies stable and supportive relationships. This sense of community applies to your work environment when it appears in this position. Possibly, you have made new friends at work or the atmosphere there has been particularly positive lately. There may also be work gatherings such as office parties in the near future aimed at bringing you closer to the people with whom you work. If there are, these events are likely to result in closer bonds between you and your colleagues.',
    reversed_career_en: 'When reversed, the convivial nature of the four of wands is subverted. As a result, it might be that, at work, your relationships are under strain or have been harder to form. This difficulty can apply in a general sense to your office’s atmosphere; alternatively, it may be in reference to a specific moment or point of tension at work. For instance, there may be office events approaching, but they will likely not go as planned. Instead of increasing comradery, they might have the opposite effect. If there are no specific concerns in your work setting, it is likely that the card is highlighting the general state of your office. Perhaps the atmosphere at work is harsh or unfriendly. Regardless, expect ruder behaviors from the people you work with and be aware of them in yourself as well.',
    upright_finance_en: 'The four of wands here not only represents financial stability, but it also indicates that you can be spending that money on loved ones. You might be buying gifts or taking people you care about out for dinners or drinks. These are good financial decisions. They might not increase your financial wealth, but they are beneficial to your social relationships and thus you can embrace them. Do not go overboard on anything, but so long as you spend within your means, the cards are encouraging you to treat those around you.',
    reversed_finance_en: 'You might be struggling against a poor economic situation if you find the four of wand here. Your financial troubles are likely linked to your personal relationships. It is possible that family expenses are weighing you down at the moment. You might be having a particularly difficult time making ends meet at this time due to these unforeseen expenditures. Be wary of friends or family asking for money that you cannot afford to give. Ask whether the money is necessary or just a desire on their part. If it is the latter, consider trying to rein in your finances first before assisting them.',
  },
  'wands-5': {
    astrology: '',
    yes_no: 'neutral',
    upright_general: 'From the image on the card, the symbolism in the Five of Wands suggests that there is form of conflict in one’s life. This may be an existing conflict or one that is brewing and may eventually blow up in one\'s face. It may also depict a problem in communication, for example in a situation where no one really wants to listen to the other - meaning that no agreement or understanding takes place. The five men may signify problems in a group of people who are not patient enough to listen to what anyone else is saying. They only want to be heard, and since none of the others will listen, they all argue at once.',
    reversed_general: 'The Five of Wands reversed meaning can be that your natural method of dealing with disagreements is avoiding any kind of conflict by getting away from that place as fast as you can. Sometimes this can be regarded as a good thing, but other times, it may lead to a number of issues that are brewing up within you, for which you will have to address soon. On the other hand, it can also mean that you have worked through your troubles and that you do not have any more issues to worry about.',
    upright_love_en: 'Action is required of you now when it comes to your love life. If you’re single, you may find that the one you desire can have many suitors, and you may have to compete for their affection. Make sure not to be carried away by this, and become too forceful; this can discourage your potential partner instead of drawing them closer. Should you already be in a relationship, there may be some small conflicts. Beware that what initially starts off as playful banter can turn into explosive arguments when either of you are stressed. It’s likely the arguments here are not too serious. Nonetheless, they will require some lightheartedness to remember how inconsequential they actually are to your happiness. Keep things playful.',
    reversed_love_en: 'Issues of how you deal with conflict can affect your relationships now. If you’re in a relationship, ensure that you haven’t been bottling up your resentments to avoid conflicts that the two of you need to have a smooth partnership. Eventually avoiding difficult conversations lead to an erosion of trust. Remember that every person has the right to their needs, and having needs does not make you any less lovable. If you’ve been doing the hard work of expressing yourself honestly with your partner however, you may find that misunderstandings are clearing up. What were once arguments may disappear once honesty and clarity have been achieved.',
    upright_career_en: 'If you find the five of wands in this position, the conflicting and competitive nature of this card applies to your career. This might be a permanent condition as a result of your line of work. This card is common among people working in industries such as sales, banking, and athletes. If that is not the case and your job does not have a competitive element, it is likely a temporary state as a result of conflict over specific issues. You might be fighting against one individual for a raise or position. Regardless of the specific conflicts you face at the moment, you will have to contend with the egos of others. Thanks to the five appearing in the upright position here, it is clear that you are capable of defeating the challenges in front of you and banishing what is attempting to block your path. Remember, you are able to succeed, but you must fight for that victory.',
    reversed_career_en: 'A reversed five of wands here means that the conflict and competition which has been in your work-life recently is ending. It might be that you are moving to a less competitive industry or the environment around you is gradually becoming more friendly and relaxed. Regardless, this is a welcome change. It is a reprieve from your recent work conflicts that will allow you to invest your energy in other aspects of your life.',
    upright_finance_en: 'You might be in a time of financial instability if you see the five here. It is temporary, but you must battle your way out of it. This battle can be in the form of needing to work particularly hard or otherwise exerting significant effort to control your financial state. If your current state is not imbalanced, it might be that you are going to argue about money soon. This argument could be either with someone you love or with a stranger such as a clerk or a shop assistant. You might find that simple tasks such as making a return or getting reimbursed is stressful and rife with disputes.',
    reversed_finance_en: 'The reversed five of wands here has two potential meanings. The context in which the card appears is crucial as it indicates which of these two meanings applies to you. Surrounded by supportive cards, it can mean a turn away from financial stress. You have completed a battle against your own finances and are about to enter a more stable time. Without the support of other cards, it can mean an escalation in conflict over money with loved ones. In that circumstance, any debates you might be having with those around you about money are likely to increase and persist.',
  },
  'wands-6': {
    astrology: '',
    yes_no: 'yes',
    upright_general: 'This particular card is all about public recognition, victory, and success. Not only have you managed to properly succeed in achieving all of your goals, but you are also being publicly acknowledged for them and the results that you’ve managed to attain. You may have received an award or some sort of public acclaim. The card is indicative that you have managed to harness the strengths and talents that you have within you in an attempt to bring a particularly successful outcome in your life. You have managed to properly get through the confusion which is brought by the card before this one – the Five of Wands, and managed to properly minimize distractions, thus successfully focusing on your goals and achieving them.',
    reversed_general: 'When the card is reversed, this suggests that you might find yourself doubting all of your abilities as well as your overall potential to achieve any kind of success. You might be feeling particularly negative about your entire self as if you have failed others as well as yourself. This is a symbol that means that you lack the confidence and drive that you need to achieve. You need the overall support as well as recognition of third parties in order to pick you up, to emotionally provide you with some much-needed strength.',
    upright_love_en: 'If you’re single, the 6 of Wands tarot love meaning signals that success is coming your way. It may be that others find you especially attractive right now. If you’ve been searching for someone, they may be more receptive to you than usual. All it takes is you making your approach. If you’re in a relationship, and you’ve been working together towards something, like moving in together after a long distance relationship, or buying a home, these goals are likely to come into fruition. The future between you seems bright, and can bring the two of you much joy.',
    reversed_love_en: 'Your confidence may be low right now; the reversed 6 of Wands tarot love meaning can suggest that you aren’t getting the kind of love that you believe you deserve. You may be feeling looked over, and rivals who don’t have the same loving, caring attitude that you do are finding themselves successful instead. Oftentimes, what is needed is an attitude change; ensure that this does not turn into bitterness. Confidence and positivity are attractive, and negativity often repels others. If you’re in a relationship, you or your partner may feel unappreciated or neglected.',
    upright_career_en: 'This six of wands is generally a very positive card that signifies success and self-confidence. These principles apply to your work-life when it appears in this position. You have likely reached an achievement at work of which you are particularly proud of. Rewards are also likely to come your way; it can mean a promotion or raise is forthcoming or recently occurred. If you recently completed a project, it will likely have good results. Whatever battles you have fought recently have been resolved in your favor. Savor this moment of contentment and confidence. Do not let your assuredness venture into egoism, but you can celebrate the end of previous conflicts and enjoy your current position.',
    reversed_career_en: 'When reversed the success generally associated with the six of wands is subverted. Instead of indicating triumph, in this position, the six of wands represents failure and a lack of ambition regarding work. It might be that you were passed over for a promotion or raise. If there was a recent conflict or competition at work, it likely did not or will not resolve itself in your favor. If there have not been such specific moments of tension, the six might be in reference to your general feelings at work. These feelings will manifest as a sense of stagnation or disinterest in projects. It could be that owing to a lack of drive, you feel stuck in your current position. Regardless of the exact context, this is a sign of underachievement.',
    upright_finance_en: 'You are in a solid financial position if this card appears here. Thanks to your dedication and perseverance in times of trouble, you are currently enjoying a moment of peace and financial stability. This is a time to appreciate the hard work you have put in and to value their rewards. Feel free to indulge in moderation, but be wary of being too confident. It is never wise to be frivolous with your purchases. Heed this general warning and embrace your success.',
    reversed_finance_en: 'If the six of wands appears to you in this position, take a moment to reassess your finances. There has likely been a downturn in your financial situation. This can be due to a single negative event or represent the state of your economic affairs more broadly. If it is the former, an investment that you made may not have yielded results, or a purchase you made wasn’t what you thought it would be. If there have not been individual investments or purchases that have decreased your financial holdings, it is likely that your money is dwindling more slowly. Though it might not be a crisis, you may be going through trying times. It can be hard to muster the confidence to trust that things will improve. Work to be productive and proactive about your finances.',
  },
  'wands-7': {
    astrology: '',
    yes_no: 'yes',
    upright_general: 'The Seven of Wands has a similar in meaning to the Five of Wands; both cards indicate struggles after the initial fulfillment and satisfaction of an event. The Seven of Wands however is different as it is is about the struggle that you need to go through to maintain your position, rather than to attain it. This is about the difficulties we face to continue to have success. You should be ready for the competition to you defend your title, and to prove yourself. Others are going to desire the same results that you do, so you need to stay ahead of the them.There will be challenges to the success of your project or venture from an outside source. You must remain dedicated to your desires, and with a clear purpose and effort, you will overcome them.',
    reversed_general: 'The Seven of Wands reversal meaning is that you could be feeling overwhelmed by all the responsibilities and challenges that you are facing. This can make it difficult to see the whole picture. You can also feel that you have to compete and compare yourself to other people, which leaves you feeling vulnerable and inadequate. The Seven of Wands reversal meaning can also reflect your feelings of being criticized and judged constantly by others. Your friends and family could be questioning you about your decisions and choices, and you feel overwhelmed by their judgement. Avoiding conflict and backing down is common with the reversed Seven of Wands. This can lead to unhappiness because you run away from activities and relinquish your goals, when you are challenged by anyone. Remember all that you fought for to be here, and think carefully on whether you truly believe that is worth giving up now. Another reading of the Seven of Wands reversed can also be that you are being too aggressive when you are protecting yourself and damaging your relationships by doing so.',
    upright_love_en: 'You may have to set boundaries when this card comes up in a love tarot reading, even though it may create some uncomfortable situations. If you’re with a partner, you may find yourself in a situation where you must fight for your relationship. There may be objections from other parties; family, other suitors, friends that oppose the two of you being together. You may have to put in a lot of effort to make the partnership last, despite many external things in your environment working against the two of you. Despite all these factors, you may be filled with confidence that this is the right thing to do. Hold on to this feeling, it will help keep you energized when the going gets tough.',
    reversed_love_en: 'Too much defensiveness can be working against you. The reversed 7 of Wands tarot love meaning can suggest that the relationship that you are working so hard to defend can indeed be on shaky ground. Others around you may see this clearly; concerned about your well-being. You may instead be brushing off these concerns, and perhaps be in a period of denial. Love may be making it difficult for you to see the truth. Alternatively, even if you two are together for the right reasons, you may find it increasingly more difficult to remain together amongst the external forces that are trying to pull you apart.',
    upright_career_en: 'In general, the upright seven of wands signifies challenges and perseverance. If the seven of wands appears here, these ideas apply to your work life. Though they might sound a bit frightening, this card doesn’t need to be negative. When upright, this card indicates that you are capable of solving (though perhaps caught off guard by) the issues you are about to face. Others may be attacking you, or envious of your position at work. Embrace your inner confidence and proceed without fear. Challenges either to your position or to your morals can be particularly common now. Fortunately, you have the strength to push past any fears or concerns and successfully stand up for both yourself and your beliefs.',
    reversed_career_en: 'When the seven of wands appears in a career reading, your attempt to stand your ground may not be working out. This can come from a lack of preparation. You may not be ready to defend your past victories, your principles, or your position. Right now, it is crucial that you protect your job position or business, but you are not willing or ready to do so. People can oftentimes become envious of success, so it is not enough to rest on your laurels. Sometimes, such as now, you may need to be on guard for people attempting to undermine you. Whatever choices you have made recently have left you vulnerable to someone else coming in and stealing the opportunities you tried to build. Be wary.',
    upright_finance_en: 'The seven of wands in this position and orientation relates to success in long term investments. This can mean that you are profiting off of previous efforts and/or will in the future. You likely are demonstrating financial foresight at this time. Though your position is currently stable, you are conscientious of how fleeting this stability can be and are taking steps to protect your earnings. This financial planning can be in the form of starting a retirement fund, buying a house, or otherwise starting to save more. Regardless of what form your investments take, these choices will serve you well in the future (as they may have previously). The seven of wands is also associated with the jealousy of others; so, do not be surprised if you find people coveting your financial success.',
    reversed_finance_en: 'Beware of frivolity if you find the seven of wands here. Do not let yourself be over-confident in your financial stability. Regardless of your income, economic dips are a part of life. The seven of wands is a reminder of that. It cautions against wasting your earnings on useless purchases when you should be saving and considering the future. Even if you feel inclined towards and capable of mindless spending, such activity is never recommended, especially now.',
  },
  'wands-8': {
    astrology: '',
    yes_no: 'yes',
    upright_general: 'The image depicted by the Eight of Wands means that the difficulties that were brought by the Seven of Wands are finally over. It signifies a strong level of energy which states that different aspects of your life will be trailblazing. Perhaps important news will be coming on your way, and you may experience a sudden, yet steady positive growth. The Eight of Wands meaning may also pertain to your work. There is a chance that the decision that you are waiting for will come your way soon. You need to be patient and just wait for it.',
    reversed_general: 'Just like the upward Eight of Wands, the Eight of Wands reversed meaning is generally associated with patience. There is a possibility that you are feeling frustrated about something. You might now see that what you set in motion earlier created the obstacles that you are discovering right now. It is time for you to understand that you cannot change the past. You must forgive yourself, and adapt your strategy.In terms of work, there may be an existing disagreement in your office. You need to settle this quickly in order to avoid derailing any major issue. Breathe, think and try to relax. Be patient and believe that everything will be just fine. The Eight of Wands reversal meaning on love may pertain to possible jealousy. The jealousy that you are feeling right now has no basis and will just affect your good relationship with your partner. In the aspect of Health and Spirituality, you need to improve your focus, cooperation, and determination. The energy of the card will just dissipate if you are losing your focus.',
    upright_love_en: 'Should you find your love life in a rut, you’ll be relieved to see movement and excitement once again. If you’re single, you’ll find that your romantic life is once again set in motion; a new love interest may spark a romance, and your love life can even be moving surprisingly quickly. Make sure you’re ready to take advantage of this sometimes frantic energy. If you’re currently in an existing relationship, surprises can be in store, giving the two of you some excitement in your relationship. It is likely that these surprises will be welcome ones, but other cards in the spread will help give more context.',
    reversed_love_en: 'Misunderstandings may play a strong role now, with the reversed 8 of Wands tarot love meaning. Regardless of whether you’re single or attached, make sure to think carefully about what you say or do. If you are tempted to do something, anything - instead of waiting, you may want to reconsider. Instead of pushing forward, you may be better off giving the other person time, or at least making plans. If you’re attached, life may be hectic at this moment, making it easier for communication to get lost or confused between you and your partner. Give your lover the benefit of the doubt as the two of you go through this period, and make sure to continue communicating.',
    upright_career_en: 'The eight of wands represents rapid movement forward. Applied to your career, this principle can mean rapid movement in the literal or figurative sense. Physically, this card can sometimes indicate that you are about to take a business trip. If that is not the case, it is likely a more broad feeling you have towards the progress you are making at work. You might feel like you are growing rapidly in your career. This is a positive sensation for you right now. It is like you are bursting out from your shell and are finally able to make the impact you desire. This advancement is exciting and invigorating. Go forth with confidence that you will continue to surpass expectations.',
    reversed_career_en: 'In this position, the eight of wands has two meanings that can apply to your career. Either you are not moving fast enough in your job or you have moved too quickly in the past. Take stock of how you feel. If you are frustrated by a sense of stagnation at work, this card can signal that you have missed opportunities by failing to act in time. You are not advancing because you let the opportunity to do so pass. If, however, you recently moved up in your career, it might be that you moved too quickly. This concern will manifest by feeling overwhelmed by what people are asking of you. If projects seem daunting, it might be useful to talk to someone about how they handle such tasks. You will learn to handle your new responsibilities, but it will take time and patience.',
    upright_finance_en: 'The speed associated with the eight of wands applies to your money in this position. It could seem like money is out of your hands as quickly as it came into them. This tendency is not inherently good or bad. Your ability to prosper at this time depends on your ability to remember just how much came in and how much went out. While it is particularly tempting right now, be warned against impulsive spending if you see this card here. The old adage “easy come, easy go” might merit repeating for the next little while.',
    reversed_finance_en: 'The eight of wand here means that you are likely frustrated with the speed at which money is coming in. You might feel as if there is not enough or you should be having money flow in faster. The main take away from a card is that you should be more patient and remember that everything you are doing is part of your slow march towards progress. Your small investments today will pay off in the end (even if they are frustrating now). If your job does not pay as well as you would like, it might be that you are still paying your dues. One day you may have the job (and income) you desire, but you have to be patient today.',
  },
  'wands-9': {
    astrology: '',
    yes_no: 'yes',
    upright_general: 'The Nine of Wands tarot card is one that symbolizes great hope even when one is faced by many problems that threaten to make them lose their balance. The Nine of Wands symbolizes one\'s life, which has undergone too many trials but through their determination and will, they were able to overcome them. These won battles are symbolized by the eight upright wands; however, there are still more trials that the person may face. This can be one major trial or challenge that they are supposed to face for them to reach their goals or be successful in their quest. The card is a sign of hope and encouragement that you should face your trials with courage so that you may attain success.',
    reversed_general: 'The Nine of Wands reversed shows a person who may not be a risk taker; they may not want to make a long-term move or commitment since they are afraid that they may not be able to come out of it. They are mistrustful and hence have created a boundary between themselves and others which is turning to be their own personal prison. You may be afraid that you do not have enough resources to face some upcoming challenges, which is why you may be open to running away or avoiding it.However, this is a situation that needs to change since this could be your self-created restriction to prevent you from attaining the new heights you need to grow. It encourages you to be brave, but also be careful not to make careless or hasty decisions that may cost you in future.The Nine of Wands may be an indication of a great personal fear or mentality that could affect you. Hence, it is important that you do something to deal with it before fear consumes you and prevents you from moving onward.',
    upright_love_en: 'You have prepared and strategized, and now are ready to face the challenges that are coming ahead. The 9 of Wands tarot love meaning signals that you recognize that the love you want will require much work, self-improvement, and sacrifice. In fact, this is the nature of all love. Many believe that love is only a feeling, but in reality, it comes from two lovers that are willing to adapt, and work through problems together as a team. It is constant communication and adjustment. This realization is coming to you now, and you are preparing for it. It is likely too that you are about to take a big step step forward when it comes to your romantic life. Are you about to propose? Or suggest to your partner that you take the next steps together? The 9 of wands tarot love meaning suggests that should you do the work, you’ll be successful.',
    reversed_love_en: 'All the preparations and work you have been doing in your romantic life may not be getting you the results that you expected. The reversed 9 of Wands tarot love meaning can indicate that despite your best efforts, the relationship that you have been fighting for has been draining and exhausting you. Disagreements are only natural, you are two different people after all, but make sure that you are not the only one in your relationship that is willing to do the work; both partners must be willing to compromise and meet each other halfway for a successful partnership. If you’re single, you may also want to ensure that the boundaries that you have set around yourself are not working to keep other people out.',
    upright_career_en: 'Here, as in every position, the nine of wands marks the halfway mark in a battle. You are not done with the struggles, but they will end soon. At present, you are likely exhausted. The battle rages on but you likely feel as if you are too exhausted to continue fighting much longer. Let this card serve as a reminder that whatever troubles you face in your career right now are temporary. Perhaps your workload has been particularly heavy recently, it will lighten up. Whenever your troubles ease, you will see that you had the strength to fight until the end. You can persevere but the battle is not yet won.',
    reversed_career_en: 'You might be experiencing exhaustion and professional fatigue if you find the reversed nine of wands here. Whatever battles you have fought with work recently have left you drained of all energy. Remember that work is only part of your life. Try to recharge what strength you can gather be it at work or in the other aspects of your life. Also, be aware of any failure to compromise on your part as this could be the root of your exhaustion. It is particularly tiring to wrestle with your own morals, be aware of when you are engaged in such battles for work. Whether you are struggling against your own morals are external conflicts, it might be that you are fighting hard against a current that will not abate. Understand when you are tiring yourself out by fighting a futile battle. Sometimes a change of course is the best way to end a conflict. This is not necessarily a defeat. Change is a part of development. Be self-critical to determine if you are being strong or stubborn.',
    upright_finance_en: 'The nine of wands can signal financial trouble. You are likely not in economic distress but are under some pressure. It might be enough that you are considering taking out money from your savings or other such sources (like loans or borrowing from someone). Instead of turning to dwindle your savings or otherwise compromising your finances, consider finding another source of income. (If you work a shift-job, take on extra hours or otherwise consider working overtime.) This does not need to be a permanent change. You will come out from under this economic duress soon. Until then, however, you must confront your financial situation with determination and drive.',
    reversed_finance_en: 'If you find the nine of wands here, it is a sign that you need to take responsibility for your financial situation. It might be particularly tempting now to run away from money troubles but don’t. Escapism is tempting but ultimately destructive. Don’t be swayed by easy outs that will damage your finances in the future. Do not, for example, waste money on a trip if you’re stressed about your debt. At this time, financial responsibility also means paying particularly close attention to your valuables. You might find they go missing if you do not pay enough attention to them now.',
  },
  'wands-10': {
    astrology: '',
    yes_no: 'neutral',
    upright_general: 'This card shows that you have already completed the circle of struggle. After spending too many resources and lots of energy looking for success, you have finally overcome the obstacles. The sweat off your brow was worth it - your efforts have finally been rewarded. You may find yourself living in a world of abundance where poverty and suffering have no chance to intervene.Although it sounds marvelous and satisfying, the card depicts a lot of responsibilities on your side. You are now the sole problem solver in your circle of family and friends which could even propel you into another world of challenges. At this point, you are also flooded with responsibilities to maintain your success. The businesses that you have started are flourishing and keeping you on your toes. The main problem is that these issues could overwhelm you if you lose control, which requires you to make sure that you know how to prioritize and solve the relevant ones.',
    reversed_general: 'When the Ten of Wands card is reversed, it indicates that you are truly burdened by circumstances which are not necessary in your life. Look around and see what is bothering you that will not positively impact yourself even if you rectify it. Drop them all and be a free being that can think soberly and do things accurately. Anything that does not add value in your life is not worth your time, so let it go.',
    upright_love_en: 'Love may feel like a heavy burden with the 10 of Wands tarot love meaning. Other aspects of your life, like work or finances, may have weighed on you lately, making it difficult for you to be romantic. Sometimes, the stress may make you feel like your love life is just another burden for you to carry, instead of something that can help you carry your burdens. If you’re attached, don’t be afraid to ask for help. It can ease your lover’s worries, lighten your worries, and can also be a chance for the two of you to become closer together. If you’re single, don’t be afraid to spend some time on your own; everyone needs to focus on themselves before they can focus on finding a partner. Take care of yourself.',
    reversed_love_en: 'You and your partner are meant to weather the burdens of life together, but one of you may still find it difficult to be vulnerable. Heavy burdens are not being shared, and that can lead to deterioration of your relationship. Instead of working as team, one person may be hoarding all the responsibilities, perhaps with the best of intentions, believing that it protects the other from stress, or worse, not trusting the other person to be able to help. If this is you, trust your partner; give them the chance to help you. When someone loves you, they want to see you happy, and helping you won’t be a burden, but a pleasure.',
    upright_career_en: 'The ten of wands is a card of burden. This principle can apply easily to your work life. When upright, the ten suggests that you are feeling overworked. It might be that you have too many projects for you to handle on your own. See if it is possible to delegate or share your load with others. Collaboration and delegation are your greatest aids at this time. Do not be afraid to ask for assistance or speak up about an uneven distribution of work. If your workload is not particularly heavy right now, it might be that you find the tasks at hand uncommonly difficult or draining. It is still okay to ask for a hand if you need one.',
    reversed_career_en: 'The ten of wands in this context represents an ending of work burdens. There are two ways this relief of pressure could have come about. One way you might have achieved this end was by successfully delegating work. Potentially, your realization that there was simply too much for one individual is being rewarded. Having better spread the bulk of your previous concerns out over a group, they now do not negatively impact any individual too terribly, and you are able to relax a bit. If you failed to delegate responsibility when it was required of you, you likely broke under the pressure of too many demands. Either way, you are no longer overworked and will have a quiet moment to recover.',
    upright_finance_en: 'There is a financial burden weighing on you if you find the ten of wands upright regarding finances. This can take many forms. You could be faltering on debt payments or have other outstanding balances to consider. It might be that a large expense like school or a business loan is especially pressing right now. You might talk to someone about how best to resolve these issues. Do not do anything brash or generally inadvisable, but know that a professional might have dependable solutions that will help set you up for long term success.',
    reversed_finance_en: 'The ten of wands, when reversed here, has two potential meanings. It might be that you are coming out of a time of economic trouble. If you have taken steps to resolve the core issues that were undermining your finances, the ten can signify that you are finally able to take control of the situation. As a result, your finances will improve soon. Alternatively, if you have not worked to understand what is upsetting your financial state, you might be descending deeper into economic troubles. This card is situational to your life so consider how well you are in control of your finances to determine the meaning. Sometimes the other cards can help suggest which of the two readings is correct. More likely than not, however, if you cannot answer what steps you have taken to command your finances, it is likely that you have not acted decisively enough.',
  },
  'wands-11': {
    astrology: '',
    yes_no: 'yes',
    upright_general: 'When we see the Page of Wands, we see a youth with enormous excitement and curiosity for the world. He knows what to do, he has the passion to succeed, but due to his inexperience and maybe a little fear of the unknown, his ideas remain abstract. He identifies new worlds to explore, new opportunities he could take advantage of quite easily, and he is even gifted with the "big picture" vision needed to succeed. Even with all of this, he still has the tendency to either remain dormant, or get easily distracted with one idea after the other. If he doesn\'t learn to control this, it might be that he squanders the opportunities to advance himself.',
    reversed_general: '',
    upright_love_en: 'The world is brimming with possibilities with the Page of Wands tarot love meaning. If you’re single, you’ll find yourself excited to meet new people, and explore new realms when it comes to love and romance. You may also meet someone who embodies this page in your love life. As a person, the Page of Wands represents someone adventurous and lively, who falls in love quickly, but may also get bored quickly. Because they live for experiencing new things, it may be difficult to create a long term relationship with this person, but a fleeting romance could be rewarding. Couples may also find themselves more willing to try new things; you may take classes together, discover new hobbies, and even explore new adventures in the bedroom.',
    reversed_love_en: 'If you’re single, the reversed Page of Wands tarot love meaning can signal a person who may not be suited to commitment. They may not know what they want from their lives, and are likely to be wandering and unreliable. Their fiery personality may get them into trouble as well. This card can also indicate a period in your love life when you are unsure of what you’re looking for; without a clear direction, you may run into dead ends. You may need to spend more time deciding what it is you want in a partner instead of aimlessly searching for love. Should you be in a relationship, this card can signal a time of boredom and lack fo of momentum. You’ll need to put in some effort to bring some life back into your partnership.',
    upright_career_en: 'The page of wands can be a great signal when it comes to new ventures. In the context of your career, it might mean that you are about to enter a new position or take up a new project. In either event, this card is a good sign; it signals that success and contentment will follow you in this endeavor. When the page appears, it is also an ideal time to take some risks with work. Just be wary of moving too quickly. The page represents an eagerness for challenges not necessarily a readiness to confront them. Ask yourself if you are prepared for new tasks before you start them. That being said, if you are ready, now is an ideal time to take some chances and start new projects.',
    reversed_career_en: 'The reversed page here indicates that you might be experiencing a disconnect between your desired career and your current one. This dissonance can be from a number of different causes. It could be that you know where you want to be but are unsure of how to get there. This can manifest in feelings of stagnation or ennui at work. Alternatively, you might know all the steps you would need to take to realize your goals but lack the motivation to take them. Regardless of the cause, take stock of where you are, where you want to be, and try to find out what will help you get there. Nothing is permanent; so, do not think that this current state will continue forever. It will, however, pass faster if you can realize what has been holding you back.',
    upright_finance_en: 'The page of wands hints that you might find a bit of money in the near future. This unexpected income can come in many forms. Someone might give you money as a gift, or you could get an unexpected bonus from work. While it is always fun to spend such extra cash, try to save some for the future. Your finances might experience a dip, and when they do, you will be thankful for this cushion. While this is always a wise choice, it is particularly important to keep in mind with the page of wands as he has a tendency to be short-sighted on such issues. Do not give in to the temptations of quick spending even if it feels like you are capable of doing so.',
    reversed_finance_en: 'The page of wands can mean financial instability. Likely, this instability is the result of a lack of foresight. You might have been overconfident financially in the past and are now dealing with the repercussions. Let this time remind you that fortunes, both good and bad, have a tendency to change. Next time you find yourself a little more prosperous than you expected, remember this low moment and use it as motivation to save. At present, the best you can do is weather the storm by working hard and being frugal.',
  },
  'wands-12': {
    astrology: '',
    yes_no: 'yes',
    upright_general: 'The Knight of Wands\' symbolism is straightforward. When it appears, it means a great time to get away and travel. The person should feel charged up and full of life. One is also ready to get things done. He is adventurous and can find fun things to do no matter where he is. There is never a dull moment when the Knight of Wands is around. When the Knight of Wands shows up in a reading it seems to suggest that the seeker wants to complete important tasks. One wants to impress others with one’s knowledge and skill. The card also shows up when the person is planning to move to another place of residence. If you are starting a creative project, then you should do so with lots of energy and enthusiasm. However, you should balance it with realistic and well-rounded views. You should also have a plan that takes into account the consequences of your actions.',
    reversed_general: '',
    upright_love_en: 'Someone who is full of vitality and fearlessness may have just entered your love life with the Knight of Wands tarot love meaning. They are likely to be very impulsive, charming, and passionate. But their rash and volatile nature can make it difficult for them to settle down with one person. If this card doesn’t represent a person, it can instead point to a period in your love life that is exciting, but also erratic and adventurous. You may be more prone to taking risks at this time, which can pay off handsomely. Fear of rejection may not be a problem at this moment.',
    reversed_love_en: 'You or another person in your life may be running from the idea of commitment right now. The reversed Knight of Wands tarot love meaning indicates impatience, instability and recklessness. This person may find themselves chasing after their heart’s desire one moment, but when they have it, quickly change his mind after. They may love the pursuit of romance, but not so much the simple, steady love that comes after. If you’re in a relationship, you may find that it feels unsteady right now, but this can also be due to the changes in your environment. Arguments are easy to spark now.',
    upright_career_en: 'The knight of wands is an enthusiastic card. This energy is a perfect complement for those who are starting new ventures. You are likely passionate about the new project that you are facing at work. You might be eager to take on new responsibilities. If, however, you are not starting anything new, you might be a bit frustrated at this lack of progress. The knight of wands can be a bit of a double-edged sword in that way. If you have a burst of enthusiasm but fear it might be going to waste, try to seek out new opportunities yourself. It might be that you have been waiting for things to fall into your lap when really you should have been seeking them out. Utilize your energy to advance, even if it takes extra effort on your part.',
    reversed_career_en: 'The reversed knight of wands can mean that you are directionless in your career. Unmoored,  you might be bouncing from job to job without considering what you want and how you need to get there. While unpredictability is common in many people’s careers, it is becoming problematic in yours. Routine might be intimidating or boring, but if you have a direction you want to go in, you will likely have to embrace these characteristics in your future work. This does not mean you need to settle down now, it just suggests that you start moving vertically in a direction instead of horizontally.',
    upright_finance_en: 'This card can sometimes signal that a large amount of money might be coming to you soon. It can be an ideal time to spend some money on a trip. Travel is a good way to use this influx in cash because, while you will not see a return on your investment, you will learn and broaden your horizons. Thus, travel, at this time, is not a waste of money. It is a smart, holistic choice. Do not give in to mindless spending. Use your money instead to expand your mind and take up new adventures. Investments in these types of projects will benefit you in the future whereas mindless spending will waste your good fortune.',
    reversed_finance_en: 'There is a tendency to get overconfident when we have money. This is a common urge, but if you find the knight of wands reversed here, you might be particularly susceptible to it right now. Even if you feel financially secure, now is not a good time to waste money or make large purchases. This principle is especially true in your investments. The reversed knight of wands can also signify a loss of some kind. In many instances, this will be unavoidable. Do not, however, facilitate this trend by participating in mindless spending or gambling. You are prone to lose more than you anticipated at the present moment. Thus, it is advisable to be particularly cautious right now.',
  },
  'wands-13': {
    astrology: '',
    yes_no: 'yes',
    upright_general: 'In general, the Queen of wands in a reading meaning may depict a person of extreme focus and fiery passion. She is courageous and individualistic, though at times she may appear self-centered. They have a positive and an uplifting energy; they represent someone who is willing to be by your side and stand up for you.',
    reversed_general: '',
    upright_love_en: 'This card represents an independent person, who is confident, outgoing and friendly, and who approaches love and relationships with a self-assuredness that is refreshing. She is not likely to change who she is in order to fit any other person’s desires, and generally doesn’t care what others think of them. The Queen of Wands tarot love meaning can be encouragement to be open and proud of your individuality and go out in the world and mingle. You can stop worrying about how you appear or how others perceive you and simply enjoy being around others. Your courage and self-possessed nature will draw others to you and inspire them to do the same. If you’re in a couple, you may find success being more open than ever with your partner. This honesty and frankness can draw you closer together. The Queen of Wands is also a very sensual character; this can also be a time of greater intimacy between lovers.',
    reversed_love_en: 'There’s a difference between being self-assured and self-centered. The reversed Queen of Wands tarot love meaning can represent someone whose fiery temper can occasionally go out of control, and whose fickleness and selfishness can mean that they quickly lose interest in you. They may have a hard time caring for your needs, while being demanding of satisfying their own. Should this not appear as a person entering your love life, this card can instead indicate you or your partner may at the moment be rather dominating and perhaps a touch neglectful of the other’s needs, or there may be explosive arguments in your relationship at the moment. Give yourself time to be gentle, to listen, and to address any feelings of insecurity that are lingering.',
    upright_career_en: 'If you find the queen of wands here, it means that you have both the energy and the ability to execute your ideas at work. Whatever you are facing in your career, you can approach it with determination and passion. This drive can apply to your general situation at work or might be more specific to your position. You might already be in a leading role in your career. It could be that you mentor others or are about to start serving as a role model. Regardless of the specifics, you are a force in your field. Right now, you have the energy and passion to lead others in a way that is particularly meaningful and positive. Use this time to advance in your career and to support those around you to the best of your abilities.',
    reversed_career_en: 'The queen of wands, when reversed, shows a lack of professional enthusiasm. You might be drained or unwilling to take on new tasks. This negativity towards work can affect both your outlook on your performance in your work life. While your career is only part of your life, it is important to feel satisfied with the work you do. There might be a lack of fulfillment in your general demeanor if you do not see value in your career. Thus, you should make an effort to remember what motivated you to find this job, the aspects about it that you like, and any other positive attributes you can prescribe to it. Consider making a list and reading it aloud every morning (or find some other way to work this positivity into your routine). Your outlook towards work can change, but this cloud will pass faster if you make a conscious effort to defeat it.',
    upright_finance_en: 'If you find the queen of wands here, you are able to make smart financial decisions at the moment. Whatever you choose to do is likely the result of careful planning and consideration. Do not get distracted or go too far off course (it is easy to get caught up in a spending spree), but if you focus, you are able to spend some money without serious repercussions. This might be a good time to expand your financial profile as you are able to evaluate stocks and other goods with a level head. Trust your instincts, however, if something feels wrong, it likely is. Your mind is in an ideal place to evaluate what is and is not a wise choice, trust it.',
    reversed_finance_en: 'You might not be managing your money well if you find the queen in this position. This mismanagement can take two forms; either you are being too strict about your spending or you are not being strict enough. You will likely know which is more applicable to you based on your finances (not the other cards on the table). If it is the former, ask where you could be more generous and remember that money spent on a good cause often comes back either in goodwill or in good fortunes. If it is the latter, try to rein in your spending. Be aware of every economic decision and ask yourself if this will serve you well in the end.',
  },
  'wands-14': {
    astrology: '',
    yes_no: 'yes',
    upright_general: 'The meaning of the upright position of the King of Wands represents pure energy. Unlike the other wands cards in the deck however, this particular one is not focused on pure creativity. Instead, this king is actually way more likely to take an idea and to decisively implement it himself. The King of Wands is a natural born leader of people, and he is also extremely capable. Once the king sets for himself a certain aim or a goal, he is going to conveniently stick to it in order to ensure that it becomes a reality.',
    reversed_general: '',
    upright_love_en: 'There’s never a dull moment with the King of Wands, and in your love tarot reading he can appear as an energetic, natural leader that is generous with both their time and their resources. Their fiery nature means that they may have quite a temper, but he is as quick to forget his anger as he is to incite it. With such energy, some folks may find the King of Wands to be rather exhausting, but he brings excitement to every situation. Should this card not appear as a person that is entering your life, this card can indicate a time of focus and perseverance. You may be putting extra effort into you romantic situation now, and this could have great rewards. If you are in a relationship, this card is a happy one; the love between the you is passionate and deep, though sometimes you can still have an argument here or there.',
    reversed_love_en: 'Reversed, the King of Wands tarot love meaning can point to an arrogant, aggressive and bossy bully. Should the card not appear in your life as a person in your life, you may have to consider your own actions. Have you been controlling, dominating or egotistical? There’s a good chance that if you’re facing issues with relationships and romance, this attitude may be the reason. You may be thinking you are doing the right thing, pushing others to be their best self, but even the best intentions can be soured with a forceful, pressuring hand. Everyone has their own way of learning, and you may be better off letting your partners explore their own solutions to their own problems, instead of coercing them to do things your way.',
    upright_career_en: 'The king of wands in your career reading can signal success and respect in your field. These ideas are linked at the present moment; you do not have to pick which applies to you. If you see the king, it is likely that you are in a high position. You might be a mentor to others. Alternatively, those around you might see you as a laudable person with morals and values. The king also suggests a boom in business. Your career is doing particularly well right now. This is not just a temporary condition. There is a longevity to your success. Your victories are likely the result of your ability to take chances when daring is needed and be cautious when it is required.',
    reversed_career_en: 'The reversed king of wands here can signal a lack of leadership and direction. You might wait for others to bring you things instead of chasing opportunities yourself. If you continue to wait for others to define your purpose, you might never find something that truly fits your passions. Serendipity is useful and important in many careers; it is not, however, a reliable source. Try to define your own wants and needs. If you have a goal or career in mind, things might not be going well in your career because you lack the confidence. It is important to trust your own instincts over the advice of others sometimes. Everyone views the world through their own lens; remember that someone else’s bias might cloud their vision of what you need. Trust yourself in your career.',
    upright_finance_en: 'You are good at managing money if you find the king here. You likely are in a stable situation because you can save if required but are also willing to spend when the time comes for it. This balance allows you to appreciate and protect your earnings. Continue to practice these principles. Saving money exclusively can be wise, but spending money, particularly on others, can be a gesture of appreciation. You are wise enough to maintain this equilibrium. Trust your judgments on investments and purchases. The stability and success you are experiencing now has the potential to be more permanent. Your good habits will sustain you as long as you continue to actively practice them.',
    reversed_finance_en: 'Take action if you see the king of wands reversed here. It is unreasonable to expect the universe to give you success. Take charge of your finances. Instead of hoping for luck to come your way, be proactive in seeking out economic opportunities. You can command your finances in a number of ways. Ask for a raise. Budget your spending. Seek more/different employment. Whatever makes sense to you in your position is likely best. It is easier to wait and hope money falls into your lap but rarely does it happen. Instead, try to take productive and defined steps towards your goals. You have the ability to realize your financial dreams. You just need to work for them.',
  },
  'swords-1': {
    astrology: '',
    yes_no: 'yes',
    upright_general: 'As with all the aces, the Ace of Swords indicates that one is about to experience a moment of breakthrough. With its sharp blade and representing the power of the intellect, this sword has the ability to cut through deception and find truth. In layman\'s terms, this card represents that moment in which one can see the world from a new point of view, as a place that is filled with nothing but new possibilities. It is, therefore, the best time to work on your goals - as the aces all give green lights, and are signals of waiting opportunities and new beginnings.',
    reversed_general: '',
    upright_love_en: 'You’ll find intellectual discussion particularly attractive right now with the Ace of Swords tarot love meaning. Communication with your partner and discussing important issues at the moment can be rewarding for you. You should pay particular attention to facing problems or obstacles in your relationship with clarity and honesty. You may be able to find that confronting these issues can lead to greater harmony and understanding between you two. Though sometimes discussions can become heated, it is more important to speak about them instead of sweeping them under the rug. In the long term, by learning these communication skills your relationship becomes stronger.If you’re in a relationship that has already been in turmoil, or you’re recovering from a break up, the Ace of Swords tarot love meaning can also be encouragement for you to cut out toxic people or attitudes in your love life.',
    reversed_love_en: 'Confusion and clarity can be affecting your relationship at the moment. With the reversed Ace of Swords tarot love meaning, there can be misunderstandings and assumptions, and sometimes your partner can have a completely different point of view from your own. You’ll need to work hard in order to get on the same page again. This card can also sometimes suggest painful words; make sure that your communication with your partner is not too brusque. Feelings may be particularly sensitive right now, and without some kindness, confrontations can quickly turn into fights.',
    upright_career_en: 'Since the aces always represent new beginnings, the Ace of Swords can represent a new job, position, or career that can bring you a lot of intellectual stimulation. You may find that your new environment is delightfully challenging and offers you lots of encouragement to grow your mind and your skills. You’ll likely be around colleagues that enjoy discussing new ideas, and communication can run very smoothly. Having a clear vision of what you want to do, as well as being able to express that vision can be helpful for you now.',
    reversed_career_en: 'At work, the reversed Ace of Swords signals that there can be some miscommunication at work right now, which can create trouble amongst you and your colleagues. It may also suggest that ideas that you’re generating now can be a little far fetched, and could result in failure. Make sure that you are very realistic with what you can accomplish, and don’t keep your head in the clouds. Be careful with your choice of words, and make sure you can express yourself clearly. Sometimes, this card can also signal being bored at work. Your work may be tedious and tiring, no longer enough of a challenge to keep you attentive.',
    upright_finance_en: 'You’ll need to think very rationally with the Ace of Swords in a financial tarot reading. When it comes to money, your heart and your head can say very different things. In these cases, this card is telling you to trust your brain and avoid making emotional decisions. Should a friend or family member ask you for money, or look for a loan, approach the situation with your mind first.  Do you have enough for yourself? Will you be paid back? How will money affect your relationship with that person? Rejecting a rational approach may make you feel better, but can cost you greatly in the long run.',
    reversed_finance_en: 'Handle your finances with care! A reversed Ace of Swords can suggest mistakes and unclarity around your finances. Go through your bank statements, contracts, loan agreements or anything legal to make sure that everything is right. If you don’t understand something, be sure to ask and not make assumptions that everything is just fine. There’s no harm in asking, and it’s better to be safe than sorry.',
  },
  'swords-2': {
    astrology: '',
    yes_no: 'neutral',
    upright_general: 'When we see the Two of Swords in a reading, we are encountering a stalemate. Two equal and opposing forces are joined in battle, and there seems to be no end in sight. This wasn\'t what you had in mind when you chanced to walk down this path, and you find yourself caught in the middle. Without something, or someone to intervene, this may continue indefinitely. We find ourselves in a situation where we must make a choice, we can side with one part of the situation, or we can side with the other. Neither seems particularly appealing, which makes the decision even more difficult. But unless we move past this stalemate, there can be no more progress.',
    reversed_general: '',
    upright_love_en: 'If you’re single, you may find it difficult to move ahead in your love life. The 2 of Swords tarot love meaning suggests being stuck between decisions. Are you attempting to choose between two lovers? Or love and other aspects of your life? It seems like your options are equally appealing, and instead of being an active participant in your life choices, you may be attempting to avoid a choice altogether. Be careful that the world doesn’t make your choice for you. If you’re in a relationship, something perhaps blocks you and your partner from resolving your problems. The 2 of Swords tarot love meaning also indicates a stalemate of sorts. It is not the time to ignore problems, but speak together carefully to find a compromise.',
    reversed_love_en: 'Sometimes, there is no right choice with the reversed 2 of Swords tarot love meaning. If you’re single and find yourself attempting to choose between two potential lovers, it can seem that none of them feel particularly right to you. If you’re already in a relationship, you may find yourself choosing between your lover and other aspects of your life. You may feel more indecisive and confused than ever. Painful decisions are suggested by this card, regardless of where you are in your romantic life. The longer you wait to make a choice however, the more your anxiety grows, creating further issues. Sometimes you may be forced to make a decision when you’re not ready. Making a choice now, and dealing with the outcome can release the burden you feel. Listen to your instincts.',
    upright_career_en: 'You might find yourself stuck in the middle of a work conflict. This can come in the form of having to side with one colleague or another, while all you want to do is remain impartial. Choosing one person over the other can create tension and rifts, and you may be worried about damaging your relationships with them. Sometimes, the card can mean you are trying to choose between two jobs or career paths. The 2 of Swords can sometimes also suggest that you don’t have all the information you need to make your choice yet. If you still have time, use it to research and get the answers you need.',
    reversed_career_en: 'It seems like the conflicts you’ve been experiencing at work have been escalating, and they can be creating lots of stress for you. If you’re stuck between two fighting colleagues, it seems that no matter what you choose to do, you’ll be in hot water, and that there are no right choices. Alternatively, you may find yourself responsible for big decisions at work; you can be leading projects, or making choices between two careers. There’s a lot of anxiety behind these decisions, as they seem irreversible. You probably have been doing a lot of research, but instead of helping, you’re dealing now with information overload, and things can be more unclear than ever.',
    upright_finance_en: 'Are you avoiding something when it comes to money right now? This card suggests you may be in denial about your financial situation, and you may find it easier to avoid looking at your finances completely. If you took the effort to look clearly, you may find that you’ll have to make some tough choices. Maybe you wanted that new designer dress, as well as a new laptop, but a clearer view of your bank account can show that you can only afford one right now. Whatever the situation is, just make sure you view it clearly and rationally.',
    reversed_finance_en: 'You’re finally learning to look your finances in the face, no matter how stressful the situation is. Once you recognize the reality, it becomes easier to make the right decisions. Alternatively, this card can signal that you’re not fully absorbing any financial information you’re trying to learn. Instead of helping you, it feels too overwhelming. Instead of letting that feeling push you away, go slowly. Learn a little at a time, and focus on one thing each week. You’ll get it in no time.',
  },
  'swords-3': {
    astrology: '',
    yes_no: 'no',
    upright_general: 'The Three of Swords depicts the message of rejection, betrayal, hurt and discouragement. In moments like these, we are well served by the mind. If you can think logically about it and prepare for the experience, the impact of this pain may be minimized.',
    reversed_general: '',
    upright_love_en: 'The imagery of this card is plain and simple; heartbreak is to come with the 3 of Swords tarot love meaning. This is likely to be a time in your life of tears, sadness and heartbreak. If you’re in a relationship, this can sometimes point to a breakup, a conflict, or some kind of separation. In the worst case scenario, since this card is a three, it can also point to a third party creating trouble in your relationship. You and your partner may have to face difficult problems in order to remain together. Without clear and respectful discussions and a willingness to work together, the relationship can reach its end. If you’re single, it may be that past grief and suffering is affecting your ability to date. Past wounds have not yet healed, and it’s important to give yourself time before you attempt to find love again.',
    reversed_love_en: 'With the reversed 3 of Swords tarot love meaning, lovers may find themselves settling their conflicts and forgiving one another. There is a desire here to heal, and move past old wounds, while looking forwards towards the future. For singles, this often means finally getting over past heartbreak, in order to be fully present in your dating life again. However, this card can also sometimes instead suggest the very opposite. Wounds may not be healing, but they may be repressed, so they fester and create resentment. Partners may not be able to forgive one another for past hurts. Sometimes, in these cases, it can be better for both to move on.',
    upright_career_en: 'Work can be a great source of stress, frustration and sadness for you right now. At worst, it can point to a sudden job loss, or collapse of a company. More commonly, it can signal some kind of conflict at work amongst clients and colleagues. If you’re dealing with this, make sure that you have honest and open conversations with your coworkers, while keeping things respectful. There’s likely a lot that you all can learn from one another. If you’re looking for work, or you have just lost your job, the search right now can leave you hopeless. Don’t be disheartened; if you can afford it, take the time now to recover from this period of anguish. It may provide you a more positive mindset for your job search.',
    reversed_career_en: 'Things at work are starting to become bright again. Stressful conflicts are beginning to resolve, and your outlook and general happiness are improving as well. Your colleagues may have moved on from the conflict, or the person that was causing frustration has left. Everyone at work may instead be focusing on forgiving past mistakes, and working together on the future. Communication has improved, and there may be new processes in place to avoid the mistakes of the past. Sometimes though, this card can also point towards a worsening of circumstances, where instead of putting issues behind them, they can hold grudges and remain negative. Surrounding cards will give more context.',
    upright_finance_en: 'You may be dealing with a material loss right now, or at least something in your financial life causing you a lot of stress. A breakup has both emotional and financial consequences; you may no longer be able to afford your apartment alone, or you may have to split your assets in a divorce. All these things can be overwhelming now. Make sure to be gentle with yourself, but also remember not to avoid taking care of these things. Find support; you can make it through.',
    reversed_finance_en: 'If you’ve been suffering from financial setbacks, the reversed 3 of Swords can signal that improvement is coming. You can be rebuilding your savings, or finding yourself in a better, more stable financial position than you were in before. Alternatively, this card can also indicate that the level of emotional grief after a financial loss is getting worse. If you’ve gone through a big loss, you may find it very difficult to adjust your spending habits, or give up your past living standards. Not accepting the truth of your position often makes a tough situation more difficult.',
  },
  'swords-4': {
    astrology: '',
    yes_no: 'neutral',
    upright_general: 'After the time of chaos, anger and pain depicted in the Three of Swords, the Four of Swords can signal that it is time to retreat. The Four of Swords is a moment of rest. Whether this is from a choice to withdraw, or whether it is from pure exhaustion, it is not clear. We are still tender from the wounds that were inflicted, and the battle weapons still hang above us as a grim reminder of what was lost. In order to continue and re-emerge in your daily life, you must take the time now to take a breather. There is always the faint fear that something more is bound to happen again and it is advisable that you take all chances to rest.',
    reversed_general: '',
    upright_love_en: 'With the 4 of Swords tarot love meaning, some time to rest is in order. If you’re single, your excitement about your love life may have led you to push yourself to exhaustion. You may be trying too hard to impress someone, or have been dating someone new every day in order to find someone you truly want to be with. You may feel drained, and it is important to listen to your intuition and your body to take it easy for a bit. If you’re already in a relationship, you can both benefit from taking a vacation. Sometimes, this card can also indicate the two of you needing to be alone for a while; this doesn’t spell the end of the relationship, but everyone, perhaps especially introverts, need some personal time.',
    reversed_love_en: 'If you haven’t heeded the warnings of giving yourself some rest, the reversed 4 of Swords tarot love meaning can signal that you won’t have a choice. If you’ve been chasing a potential lover relentlessly, you may find that your advances are now feeling unwelcome. You may benefit from giving this person time and space to make their own choice. Pressuring someone often creates the opposite effect of the one you desire. Alternatively, this card can also indicate coming out of a period of rest. You may feel more energized than ever! Couples who have felt that their relationship was getting a little too routine can find that their passions are reigniting.',
    upright_career_en: 'Work may have been very busy or frustrating lately. You may have been putting in your all for a long time now, and chronic stress may be taking a toll on your body or mental health. Listen to your body, and give yourself a break. If you can, take a mental health day, and spend it caring for yourself or catching up on sleep. None of us are machines, and without some much needed rest, the effect it takes on our health can be long lasting. You can return with a refreshed mind after.',
    reversed_career_en: 'You may have given yourself a much needed little break from work, but you may now be feeling ready to return. Ideally, you’ll have used this time away to reduce your stress, and take some much needed care for yourself. With a refreshed and rejuvenated time away, you’re likely to find that situations that have caused you suffering and frustration before are a bit easier to handle. Try and be more aware of your stress levels from here on out. Sometimes however, this card can also signal continuing work despite needing rest. If this has been the case for you, you may want to reconsider. Our bodies will often force us to take a break. You may also want to consider changing jobs, if the situation truly looks like it won’t improve.',
    upright_finance_en: 'Does your mind run around in circles worrying about what you have in your bank? If you’re used to dealing with financial stress, thinking (or rather, worrying) about your finances can be second nature. Try and give your mind a break. Oftentimes, letting a thought go around in circles solves nothing, and the best thing we can do for our minds is think of something else. Avoid letting paranoid ideas and negative thinking consume you.',
    reversed_finance_en: 'Your financial situation may be improving, and you may be recovering from a period of intense pressure. Perhaps bills are being paid, debts have been paid down, or expenses may be decreasing. Alternatively, pressure may be increasing, and you may start feeling overwhelmed with bills. Search for support; there may be people that can help you at this time. At times, this card can also suggest that you may not be accepting financial support despite having it.',
  },
  'swords-5': {
    astrology: '',
    yes_no: 'no',
    upright_general: 'This card indicates that you are engaging in a conflict of some nature. It can also suggest a disagreement with others, which leads to hostility and tension. Despite the fact that you think you’ve won, you might still lose in the big picture, because you have annoyed or hurt those that you have argued with, and as a result, you are on the road to isolating yourself. Perhaps, at the moment, you believed that it was more important to be right rather than appreciate and understand where the other side was coming from.Right now, it\'s important to attempt to pick up the pieces. You still have the chance to act while the conflict is still fresh. You may feel as if everyone and everything is against you. You might also lose some friends along the way. This is why you will need to make a significant decision about your point of view. What is more important to you? Mutual progress, or winning? This might require you to stand up to a conflict within yourself.',
    reversed_general: '',
    upright_love_en: 'Unexpected change and uneasy energy can be signaled by the 5 of Swords tarot love meaning. There can be an anxious and demanding feeling in the air, making it easy for arguments and fights to materialize. You and your partner may feel irritable, and without taking some care, conflicts can be easy to start. Should you find yourself in one of these, you should think carefully about your reasons for being in this squabble, and make sure that you’re not arguing simply for the sake of being right. Egos may push you and your loved one to clash without any real reason. Sometimes, this can create passion when it is sorely needed, but can be damaging should it continue.',
    reversed_love_en: 'Reconciliation after heated tensions is possible with the reversed 5 of Swords tarot love meaning. There is a desire between you and your lover to lay down your swords and find a compromise. It is likely that wounds will still be painful even if both choose to let things go. At times, this card can indicate walking away from a lover or potential relationship, should reconciliation not be possible. Though painful, this may have been the better choice if heated arguments are happening much too often. Sometimes, it is better in the long run to cut your losses and walk away before more damage is done.',
    upright_career_en: 'Conflicts are erupting at work, and considerable amounts of hostility is in the air. It can be easy right now for arguments to explode. This can come from misunderstandings, lack of communication, or poor leadership. The 5 of Swords can also signal bullying and intimidation. Whether it’s you or another person, you may be called upon to stand up for yourself or someone else. While it can be tempting, ensure that you handle the matter professionally, and don’t be afraid to pull in HR if you need to. Processes are usually in place to handle these situations. However, this card can equally point towards self-victimizing, meaning that your impression of the situation may be what is causing these conflicts in the first place. Defensive behavior usually creates a cycle of aggression, so be very clear with your own actions and how they affect this environment.',
    reversed_career_en: 'What was once a stressful and hostile work environment may be in the process of getting better. It seems that a resolution is possible now as everyone is ready to put down their swords. Compromises are made, and open communication is now possible again. If this doesn’t apply to you, this card can also suggest that an escalation in hostility is happening instead. If you’ve been dealing with a workplace bully, they may up their attacks towards you, sometimes even attempting to get you fired. Don’t be afraid to bring this up with your manager or HR, it’s their job to deal with these kinds of conflicts. Once you do though, make sure that your own behavior isn’t also a cause for concern. As long as you’ve handled things calmly and professionally, you can make it through.',
    upright_finance_en: 'You may be facing conflicts when it comes to money right now; whether it is with your partner, your family, or your friends. You’ll need to be extra cautious with your finances right now, especially when it comes to trusting others. There may be people who are attempting to take more from you than they are owed, or take advantage of you. Sometimes this card can also point to finances being tight right now; you may have to cut some luxurious expenses from your budget.',
    reversed_finance_en: 'If you’ve been dealing with tense financial situations, or even fights about money, you may see these start to dissipate and relax now. If you’ve been dealing with people that have been attempting to take advantage of you financially, you may see them distance themselves from you, or even being held accountable for their actions.',
  },
  'swords-6': {
    astrology: '',
    yes_no: 'neutral',
    upright_general: 'The meaning of the Six of Swords is that you are experiencing a transition of some kind, but one that is not happy and filled with regret. This transition will most likely be the result of decisions you made in the past, and now they are forcing you to leave something behind in order to move forward. Despite your sadness, you need to remember that moving on is the ideal option for your future.',
    reversed_general: '',
    upright_love_en: 'When the 6 of Swords appears in a love tarot reading, it can signal a struggle is reaching its end. Sometimes, this can take the form of ending a relationship, or alternatively, putting a painful chapter of your relationship behind you and reconciling. In any case, it suggests the desire to leave the past, and go forwards towards an unknown, but brighter future. If you’re single, you may be ready to leave a part of yourself behind, perhaps one that prevented you from accepting love. If you have had old wounds you’ve been nursing, the 6 of Swords tarot love meaning can be a welcome sight. You may be finally ready to leave them behind.',
    reversed_love_en: 'What do you find hard to let go of? The reversed 6 of Swords tarot love meaning suggests that the past still has a strong hold on you, despite your attempts to leave it behind. On one hand, you may know that leaving the past is something that is the healthiest for you to do, but you may be compulsively pulled back. You may choose to stay in a loveless relationship by remembering its happy moments, unable to move on from a toxic ex, or past insecurities may be holding you back from living your love life fully. Examine what binds you, and also consider what potential happy future you are willing to sacrifice for its sake.',
    upright_career_en: 'You may be putting a stressful period of work behind you. There may be relief and calm as you are heading towards a more relaxed phase of work. You should be making steady progress on your projects. Compared to past experiences, these times can be a welcome improvement. Sometimes, this card can also indicate a recent change of roles or positions into something that you are better suited for.',
    reversed_career_en: 'It seems that no matter what you do, you can’t escape your work troubles. Your workplace may be filled with stress, fights and conflicts that are draining and take a toll on your mental health. Even though you may want to leave, it seems like you are trapped in this job, and at the moment can’t find anything better. Sometimes, this card can also suggest that you may be the one creating the trouble; instead of letting things go, you may be returning to the same issues over and over again, holding grudges despite another party’s willingness to put things behind them. It’s likely that you may want to look at your own attitude and defensiveness and see whether that is contributing to your own stress levels. What can you let go of? If you do manage to leave this job, be wary that the same problems arise again. We can run away from an environment, from people; but not ourselves.',
    upright_finance_en: 'The 6 of Swords can signal movement away from financial struggles as you put that past behind you. Financially, things can be more comfortable for you, and you may no longer be under intense pressure. As you find material stability, let past experiences be a reminder to you to keep an eye out on your bank accounts. Oftentimes, we can’t run from our money issues, and it’s better to remain responsible so that problems don’t arise again and again.',
    reversed_finance_en: 'Are you trying to escape your financial problems right now? When it comes to money issues, it’s generally not possible to escape them. The only thing you can do is confront them face to face and deal with them honestly and calmly. What seems insurmountable may seem much simpler to face once you’ve done the work of actually accepting your situation. If you need it, search for a professional that can help you with your situation.',
  },
  'swords-7': {
    astrology: '',
    yes_no: 'no',
    upright_general: 'The Seven of Swords in general, is said to be about betrayal and deception. When you get this card, it may imply that you or someone else in your life is having difficulty getting away with something. There are instances when we are forced to be sneaky, hoping that we will not be discovered. When we are found out, we have to face the consequences - whether it\'s embarrassment, punishment, or worse. Sometimes this happens when there are instances when you had to think on your feet, and did something that was somewhat shrewd and out of character. Now there is a danger of the secret coming out.',
    reversed_general: '',
    upright_love_en: 'Lies and tricks may be abound with the 7 of Swords tarot love meaning. It may be important for you right now to remain cautious, especially if you’ve met someone new. You or someone in your romantic life can be dishonest right now, and in the worst possible cases, even unfaithful. If your instincts have been telling you that you are being lied to, you may need to confront this and have an honest discussion. If this has been you, consider the long term consequences of your actions. Even the kindest lie to spare feelings can grow into big problems should the root cause not be addressed. If you’re single, you may need to evaluate whether you’ve been too suspicious or untrusting of potential lovers, or on the other hand, been leading them on, or exaggerating who you are.',
    reversed_love_en: 'An end to lies and deception may be suggested by the reversed 7 of Swords tarot love meaning. Dishonesty always eventually comes to light, and this card signals that the truth is coming to surface now. If you’re the deceiver, it is in the long run more important to confess and admit to any wrongdoing. It is not easy to carry the weight of dishonesty; for it usually comes with constant anxiety of being found out. Those looking for love can be more willing to drop any pretensions or stop playing games. In the long run, this can bring you more fulfillment than having to consistently change yourself for love.',
    upright_career_en: 'There may be some shady characters in your workplace. Lies and deceit can take you by surprise. You may be dealing with colleagues attempting to sabotage you with gossip, badmouthing you to bosses, or attempting to take credit for your work. Be cautious about who you trust in this situation; it may come from where you least expect it. Sometimes, this card can also suggest you will need a certain degree of strategy to accomplish your projects. You may be the underdog here, and others may have more resources or established positions. A certain degree of working tactically can be an advantage for you now.',
    reversed_career_en: 'Truths are coming to light now, and if others have been acting untruthfully now, their lies can be exposed. Whether you’re the victim of this deceit, or you’re the one that has been unfair, guilt and shame is likely to push the perpetrator to confession and perhaps reconciliation. As long as you make amends, and face the consequences, there is likely to be forgiveness. Alternatively, the situation at work can escalate; sometimes those who are at fault are not brought publically to justice. Keep in mind, that however disappointing, one’s character will dictate their fate in the future. Sometimes the 7 of Swords is a simple statement that the strategies and the approach you’re using at work is just not working, and you’ll have to change how you handle your projects.',
    upright_finance_en: 'Be careful regarding your finances right now, as there may be some sort of trickery, scam or stealing of your resources. This can come outside of you, but you may also be inviting these situations if you are trying any get rich quick schemes, or gambling away your money on other shady deals. Stay away from things that feel suspicious or too good to be true.',
    reversed_finance_en: 'Have you been completely honest in your financial dealings? Now may be a good time to get your taxes paid, and in order before you get in deeper trouble. Or have you been a victim of theft, scams or fraud? The truth is coming to light now and there can be consequences for those that have not walked an honorable path.',
  },
  'swords-8': {
    astrology: '',
    yes_no: 'no',
    upright_general: 'The general meaning in the Eight of Swords is that of a feeling of being trapped and victimized. You may feel powerless because, in your mind, you feel that changing the situation might be beyond you. This feeling of helplessness that you have, the feeling that you have no agency in your life, has played a major role in making your situation worse.',
    reversed_general: '',
    upright_love_en: 'When the 8 of Swords appears in a love tarot reading, you may be feeling trapped; do you feel smothered in a relationship, or in a now stale partnership you cannot leave? You may feel as though you have no choices, but this usually isn’t the case if you look at the bigger picture. We deny ourselves possibilities when we are too scared of doing the hard work of communicating our boundaries or standing up for ourselves. In order to make changes, you must be the one to take action and control. Freedom doesn’t come with passivity. If you’re single, this card can also point to being too passive in your love life. You may be unwilling to venture and meet others, hoping that the solution to your romantic life will be a person that can sweep you off your feet. This often doesn’t yield results.',
    reversed_love_en: 'As you take off the blindfold, take a long clear look at your romantic life. The 8 of Swords tarot love meaning can suggest that your perspective is changing now that you have a more clear and objective understanding of your relationship. Anxieties may be lifted, and it can now be clear to you what needs to be done in order to feel happier in your romantic life. If you’re single, you may find yourself more willing to take your love life into your own hands. Fears and anxieties that have blocked you from truly pursuing romance can be lifted.',
    upright_career_en: 'Your career isn’t quite what you thought it would be. Yet because your job is tied to your means of living, you feel that you can’t leave right now. You may feel you do not have a back up plan, or other positions, jobs or career paths available to you right now. If you’re looking to switch career paths, it may take some education, but this can be difficult without having a steady income. While it may feel like you don’t have options, you may just need to think outside the box. Anxiety may make you feel like you have less options than you actually do. Ask for help, look over your budget, turn a hobby into a business, find a reputable place to get a student loan; there are likely many options, where you don’t have to keep suffering.',
    reversed_career_en: 'It may have taken a while, but you have finally found release from your anxiety about your career. Things can be a bit easier now, and your vision is less clouded from stress or fear. Sometimes, this card can suggest a new job or position that you have attained, one that allows you to realize your full potential. The reversed 8 of Swords however, can at times also signify just the opposite. You may instead have lost all hope, resigned yourself to the idea that no matter what you do, this is the only path for you. Every day may be a struggle. Remember that you do have the power to change things, so long as you open your eyes to all possibilities, and don’t let fear take over. Nobody will save you except yourself.',
    upright_finance_en: 'You may feel like things are closing in on you right now when it comes to your financial situation. Anxiety about the state of your bank account can alter how you perceive the reality of the situation. If you’re looking to make more cash, you may have more tools to do so than you think. Do you have a talent that someone else would pay for? Are you a talented writer? Ask if local businesses need a writer for their blog. Read tarot cards? Start charging for readings at your local cafe. There are so many ways to better your situation, you’ll just need to be a little more creative.',
    reversed_finance_en: 'The reversed 8 of Swords can signal that your anxieties about money have either lessened, or intensified. You may finally be learning to see all the possibilities that are available to you, or alternatively, your fears and anxieties have just continued to get worse. You will need to address these fears before they continue to do damage to your mental health.',
  },
  'swords-9': {
    astrology: '',
    yes_no: 'no',
    upright_general: 'The Nine of Swords is often associated with fear and anxiety, about all the things that worry you and keep you up at night. Sometimes this card can be associated with trauma - one which may be shameful for you to confide with others about, and all the psychological responses that come from experiencing that trauma.',
    reversed_general: '',
    upright_love_en: 'Anxieties and fears can escalate with the 9 of Swords tarot love meaning. Some nightmare situation may be keeping you up at night. Oftentimes, this card suggests that the fears are not as terrible as they are in your head. You may be struggling with guilt, remorse, insecurity, trusting your partner, or mental health issues. You’ll need to understand for yourself whether these feelings are truly rational. Anxiety may be causing you avoid looking at the problem and facing it head on, but if you took the effort to open your eyes, you may find that you can work through these issues. If you’re single, past relationships can be a source of remorse, sadness and regret, and these feelings must be worked through before going into another relationship.',
    reversed_love_en: 'You may be ready now to be honest and face the truth with the reversed 9 of Swords tarot love meaning. If you’ve been suffering quietly, being honest with your partner can be give you the release you need. It is not easy to carry the weight of your anxieties alone, and if your partner is supportive, they can be there to give you the reassurance you need. Through discussion, you may learn that the things that are keeping you up at night are not as bad as you had thought they were. If you’re single, you may be working on yourself, so that you can enter a healthy and loving relationship again. The time is almost there, and you may be feeling ready to find love again.',
    upright_career_en: 'Stress and anxiety are the biggest features of your current work situation right now. Sometimes this card can also point to paranoia, and that things are really not as bad as you believe they are, which can be good news. Regardless of the circumstances, work may feel incredibly overwhelming right now, and you may reach burnout if you continue without changing anything. If your stress is due to external factors, you may need to take concrete action, such as searching for somewhere else to work, or changing your career path. If your stresses are mostly due to anxiety and mental health issues, you may need to learn how to think more positively. Internal shifts may be needed, and you may benefit from the help of a professional or a trusted friend to give you a more objective view of everything.',
    reversed_career_en: 'The issues that you’re facing in your workplace can either start to lesson, or get worse. Ideally, you have figured out that your work situation isn’t as bad as it seemed, and you only needed to develop some changes in your attitude, perspective, or behavior in order to solve the problems you’ve been dealing with. The negativity you had about your work is fading away towards brighter days. Alternatively, your situation truly may have collapsed and gotten much worse. You may be truly burnt out, unable to go to work because of your stress. To understand the whole picture, look at other cards in your tarot spread.',
    upright_finance_en: 'Financially, you may be under a lot of pressure and stress right now. The suffering you’re feeling is real, but the 9 of Swords often points towards anxiety and worries that come from exaggerating the situation instead of looking at it realistically. If this is the case, your panic may be from your own negative thinking. It may be helpful to enlist an outsider’s perspective to give you advice on what you can do.',
    reversed_finance_en: 'Sometimes, the reversed 9 of Swords can indicate the stress around your financial situation is getting better - or worse. Other cards in your tarot spread will give you an indication of which. Either you’ve learned how to get a more realistic view of your money, or it’s gotten worse, and your fears may now be realized. Find help, others can be useful for support right now.',
  },
  'swords-10': {
    astrology: '',
    yes_no: 'no',
    upright_general: 'The Ten of Swords indicate a major disaster of some sort. It shows that a certain force of extreme magnitude has come to hit you in your life - one that you may have not foreseen. There is a sense of betrayal that is indicated here, for the character is stabbed in the back. This seems to be a reminder that despite how much we try, we cannot control everything - there are things that are beyond our ability to change. Here, this situation is unavoidable.',
    reversed_general: '',
    upright_love_en: 'Unfortunately, the 10 of Swords tarot love meaning can indicate a relationship that is coming to its end, or a period of time filled with suffering, bitterness, grief and pain. Likely, the relationship was headed towards failure of some sort, and you may have already seen it coming. Sometimes, this card can also suggest betrayal, indicating infidelity. While this period of time may be incredibly difficult, you’ll need to come to terms with it and accept the inevitable end. Singles may be dealing with similar feelings that have lingered after a past relationship. Only with acceptance, can you truly heal, and move forward. The worst has happened, and despite how it looks, it can only get better from here.',
    reversed_love_en: 'You may have many scars from past romantic wounds, but the reversed 10 of Swords tarot love meaning can suggest that you may be on your way towards healing. If you are in a relationship, the bonds between you and your lover that seemed permanently severed before may be healing. In other cases, the relationship may have already collapsed, but you have managed to cope. There may still be feelings of anger and despair, but also recognition of the lessons that this heartbreak has taught you. It is likely you’ll be able to recover from this situation with more strength than ever.',
    upright_career_en: 'In the worst case, you may be reaching the end of your current job right now, as the 10 of Swords signifies endings, and cutting one’s connections. Sometimes, this card can also suggest that you may be dealing with office politics that have left you defeated; perhaps colleagues have been spreading gossip. Alternatively, you may instead have been working very hard, pushing yourself to collapse, and forced to take a rest. All of this may have been necessary for you to grow; when you go forward and heal from this ordeal, think of what you have learned, and know that you will survive.',
    reversed_career_en: 'Your path to healing from past stresses is getting started. You may have changed jobs recently, or left a job that was creating lots of frustration, anger and resentment for you. Whatever had happened, the worst of it is now over. You can breathe a sigh of relief that what is ahead will be easier to deal with. However, this card can instead suggest that this stressful time is getting worse, and that unless you do something to distance yourself from it, you are on the verge of collapse. You’ll need to weigh whether your mental health is worth the amount of suffering you are going through.',
    upright_finance_en: 'Your financial situation may be grim. You may have put your money into something that has not yielded fruit, and you may be dealing with losses right now. Ensure that you cut all expenses related to this failing endeavor, and instead be cautious about your resources. Avoiding risk can be beneficial for you now.',
    reversed_finance_en: 'You may have been on the brink of financial failure, but you may have been able to narrowly miss it. You can also be recovering from a loss of resources, like bankruptcy or a divorce, and you may finally be getting on stable foundations again.',
  },
  'swords-11': {
    astrology: '',
    yes_no: 'neutral',
    upright_general: 'Bright and alert, the Page of Swords is someone who never seems to run out of ideas. She is curious, always asking questions, and gifted with a sharp tongue and quick wit to match. Her aptitude for language also makes her an incredible communicator, and with her love of ideas, you may find her always engaged in some passionate debate.',
    reversed_general: '',
    upright_love_en: 'As a person, the Page of Swords tarot love meaning reflects a curious intellectual, whose flighty, nervous energy may border on being anxious. In relationships however, they may be scared of emotional confrontations, and can likely be completely avoidant if they are faced with them. As an emotional state or a quality, the Page of Swords tarot love meaning can signal a relationship that is more cerebral, where lovers are more likely to love heady discussions, but are perhaps a bit more wary of emotional intimacy. One partner can also feel that their emotional needs are not being met. Sometimes, it can also signal small or petty disputes with your partner, which can turn into bigger conflicts should they not be handled properly.',
    reversed_love_en: 'The person represented by the Page of Swords tarot love meaning is someone who may lack empathy, sensitivity or depth, or can be someone who can be argumentative or defensive. They may delight in “being right”, but this can come at the expense of harmony and care for the feelings of others. This card can also suggest a failure in communication between partners, or perhaps even a misunderstanding creating paranoia. For your relationship to flourish, partners will have to learn some degree of tolerance for different viewpoints, flexibility and find a desire to cooperate, rather than create conflict.',
    upright_career_en: 'When it comes to your career, you may be someone who is intelligent, innovative and ambitious. You may have lots of energy and many ideas to put into your career. Since this card is a page, this does point to some sort of apprenticeship, or new experience, meaning that you may either be in a period of training, school or the start of a new job or career path. With your ambition, you have lots of goals, and you’ll likely have some extra education, or experience so that you can reach those goals.',
    reversed_career_en: 'You have lots of energy and curiosity, but right now it’s not really directed at anything. With no outlet, it seems like you can’t quite make up your mind about what it is you actually want to do for your future. You may move from one job to the next when you get bored, or decide it’s not for you. Oftentimes, to really get the full depth and experience of working somewhere, you do need to commit for a long time. Sometimes, this card can also indicate having lots of big ideas, but zero follow through. Without action, nothing ever comes to fruition. Get working! This card can also point to an office gossip, or a rude individual who uses their words to hurt others.',
    upright_finance_en: 'You may be full of great ideas about how to stretch your finances, or how to make more money, but whatever ideas you may have may be in the very early stages. If you can, try and draw from people that may have more experience than you. You may also be very curious about finances at this time; it’s a complex world, and the more you understand about it, the better you can maximize your earnings. Take some time to study retirement fund options, stocks, bonds and other financial products, or find a financial planner that can help guide you.',
    reversed_finance_en: 'Your ideas about making the most out of your money may not be practical ones, or they may be all talk, without a plan for taking action. It may also be that all the research you put into bettering your finances isn’t really going anywhere. You may feel rather overwhelmed about what you should do next instead of just doing something. What are you overanalyzing?',
  },
  'swords-12': {
    astrology: '',
    yes_no: 'yes',
    upright_general: 'When we are thoroughly obsessed by a certain idea and strongly wish to manifest it, we are oftentimes so blinded by the actual desire for its fulfillment that we fail to note the difficulties which we may come across, or the actions and consequences that it could bring. The Knight of Swords is a very powerful figure that is full of life as well as energy. This needs to be balanced with a proper and actual realization of compassion and responsibility.',
    reversed_general: '',
    upright_love_en: 'The Knight of Swords finds it particularly difficult to commit to a partnership. This person requires a lot of intellectual stimulation, and without it, can quickly become bored. This person can also be someone that finds it difficult to become too emotionally intimate with another person. If this doesn’t represent a person in your love life, the Knight of Swords tarot love meaning can point to a situation in which you’ll need to muster your courage, and quickly make decisions and take action. This can come in the form of making a commitment or a romantic proposal to a suitor, or even winning a lover back should they be on their way out of the relationship.',
    reversed_love_en: 'Be wary of the reversed Knight of Swords in a tarot love reading, as this person may be aggressive, controlling and perhaps even a bully. Convinced that they are right, they strong-arm others to do things their way regardless of how much it hurts the other person. They may have very little sympathy or understanding, and can delight in getting themselves into arguments, sometimes not just to have a debate, but to intimidate and pressure others. If this doesn’t represent a person, the reversed Knight of Swords love tarot meaning can simply suggest intense arguments, conflict and disagreement. Should these fights become commonplace, it may be better for the two of you to part ways.',
    upright_career_en: 'When you combine your lofty ambitions with your determination, and almost singular focus, you’re sure to get what you want. Nothing quite scares you off, when it comes to your job. You’re likely to be excellent at what you do, going after your projects and completing them with almost ruthless efficiency. This may intimidate others sometimes, but this may not be a very big concern to you. If this doesn’t represent you right now, you may be called to use this Knight’s energy to go after something you want in your career. If you’ve had your sights on a promotion, a new job, or a particularly exciting project, go for it! Make a big move, and get someone’s attention. Be as determined and daring as the Knight of Swords, and you can find success.',
    reversed_career_en: 'While upright, the Knight of Swords’ ambition and drive left people in awe, in reverse, the Knight may instead come off as ruthless or vicious. Beware of hurting others as you complete your career goals; you may instead get a reputation for being a cutthroat, not caring who else gets hurt as long as you get what you want. Sometimes, others may also find you arrogant, and pushy when it comes to your ideas. Do you always need things to go your way? Do you ignore or dismiss the ideas of others without giving reasons? Sure, your methods may yield the results you want, but in the long term, consider what happens when nobody is there to support you. Try and be a bit more careful with your language and how you communicate.',
    upright_finance_en: 'You may be very focused on your finances right now. Perhaps you are concerned with saving up for something big, or you just want to optimize what you’re saving. You are likely putting a lot of energy into doing this. With enough focus and determination, you’ll be able to meet your goal.',
    reversed_finance_en: 'Are you so focused on money that you sometimes cross the line when it comes to acceptable behavior? The Knight of Swords reversed is someone whose determination is so strong, that they stop at nothing to earn a buck. This can sometimes point to behavior that can be illegal. If this doesn’t represent you, someone in your life may be playing the part of this reversed Knight of Swords, so be wary with who you allow in your circle.',
  },
  'swords-13': {
    astrology: '',
    yes_no: 'yes',
    upright_general: 'The Queen of Swords is an archetype of an older, wiser feminine intellect. She could be thought of as the most masculine of the all the queens, and may come off as quite stern and emotionless. This card represents the importance of making judgments without relying on emotion alone. The Queen of Swords beckons you to look at all the facts before making a decision. This queen does have compassion, which is why she has her hand reaching outwards in offering, but she wants to connect to people using an understanding that is intellectual.',
    reversed_general: '',
    upright_love_en: 'The person represented by the Queen of Swords can be a loner; she is very discerning about the people she surrounds herself with. Her intellect is sharp and perceptive, and her determination can be rather intimidating to those that do not know her well. Underneath her shell however, she can be loving and loyal, though she may still prefer to avoid grand romantic displays. If this is someone whose heart you’ll like to win, you’ll need patience, as this queen does not easily let down her guard. If this card doesn’t represent a person, the Queen of Swords tarot love meaning can suggest a time when you are looking for both independence and self-sufficiency alongside your partnership. This queen values her own space and identity. You may have to make some adjustments to create clarity and boundaries in your relationship.',
    reversed_love_en: 'A reversed Queen of Swords is someone who is bitter, manipulative, overly critical and can be downright cruel. This person can represent you our your partner at this particular time, or alternatively, someone outside of the relationship that is attempting to interfere. Sometimes, this person’s nastiness can be the result of trauma, and because of this, if your partner is demonstrating these traits, it can sometimes be the result of unresolved trauma that is coming to the surface. If you are single, there can be the chance that you have just gone through a break up, one that has left you feeling vengeful and unforgiving. These beliefs can be toxic; learn to use your experiences to overcome them, instead of being consumed by them.',
    upright_career_en: 'The Queen of Swords can point to either someone more senior, or yourself in a career tarot reading. This person is wise, honest, and may be a source of constructive criticism. They can offer great advice on how to proceed in your career. If this card represents you, you may be at a period in your life when you are able to get much respect from your colleagues. You are able to effectively communicate your sharp ideas, as well as combine them with a strong place of empathy. You’ll likely have a strong reputation due to your integrity and your fairness.',
    reversed_career_en: 'Is there someone at work who is holding a grudge against you? The Queen of Swords reversed can indicate an overly critical person who uses her words and her intellect to create suffering. She can be harsh, and sometimes downright cruel with how she expresses herself. If this is you, you may need to learn how to communicate better. Can you be honest while also caring for another person’s feelings? Can you address your concerns about a project without blaming someone? These may actually benefit you by helping others better digest your ideas. Avoid being too negative.',
    upright_finance_en: 'When dealing with financial matters, you’ll need to act with consideration, logic and wisdom right now. Have a clear balance between heart and head. If you’re being asked to help with someone’s financial situation, look at things fairly, from both your perspective and theirs. This can usually mean being able to give assistance, but with boundaries. Put together a contract, or a payment plan; set some rules. This queen is also sharp and perceptive; noticing all details. Make sure you have clarity about your financial situation.',
    reversed_finance_en: 'If you’ve been communicating about finances poorly, you may be dealing with the consequences right now. Lack of clarity about your own financial situation could also be the culprit. Perhaps you lent money to a friend or a family member, who has failed to pay you back, or you may have given or spent more than you could actually afford. You’ll need to make sure that you’re more clear about your own boundaries and limits next time.',
  },
  'swords-14': {
    astrology: '',
    yes_no: 'yes',
    upright_general: 'The King of Swords appearing in a reading suggests that you should remain objective in your current situation - you must establish truth by sticking to the facts. The King of Swords and his intellectual power implies that you will need to use your intellect to make your point known and attain your goals. Besides your experience and education, you should be sharp and observant, to see deeply into problems that come your way.',
    reversed_general: '',
    upright_love_en: 'The King of Swords is someone who is cool, controlled, as well as ambitious. Though they have emotions, they can be very restrained. They instead rely on their intelligence and their logic. In romance, they approach their relationships ethically and respectfully. They may not be very romantic, and are likely to express themselves very bluntly. Should this card not represent a person, the King of Swords tarot love meaning can simply indicate high standards when it comes to romantic partners, especially intellectually. You and your partner at the moment can also be challenging and pushing each other to be their very best.',
    reversed_love_en: 'Reversed, the King of Swords can use their sharp intellect for selfishness. The wisdom and morality that guided his actions in the upright position is gone, and they can instead be frightfully selfish, and even abusive. This person also allows his emotions to run uncontrolled, flipping quickly from being cold and distant, into fits of rage. As characteristics or qualities, the reversed King of Swords tarot love meaning can signal that you may be exhibiting these qualities in your relationships. You may need to show more restraint and forgiveness to your partner, or else you may lose them. This card can also suggest low standards when it comes to potential relationships; try not to be swept away by feeling, but use some logic to evaluate whether someone is a good partner for you.',
    upright_career_en: 'The King of Swords is someone with high standards, and demonstrates them in his own work. Though they may seem a bit stern, this person acts this way to make sure you achieve your career goals. They challenge you to be your best self, while remaining true to their own principles. Should you choose to take his advice, you’ll be able to progress far in your career. Alternatively, this person may also represent you, or a point in your career path. Give yourself and others high standards, and push yourself to be the best that you can be. Having some routines and processes can also be beneficial for your work right now.',
    reversed_career_en: 'Your workplace may not be a very pleasant place to be right now. The reversed King of Swords signals a person at your job who is dominating, aggressive, and power-hungry. They may be in a place of power, and they can use that power for all the wrong reasons. If this doesn’t represent a person in your workplace, you may have to take a closer look at your own behavior. You may find that it is easier to lose your cool, and fail to act with as much integrity or logic as you usually do. At this time, you may also be suffering from lack of self-discipline; not just losing your cool, but your motivation and energy.',
    upright_finance_en: 'The King of Swords pushes you to challenge yourself and be very disciplined when it comes to your finances. Are you really doing all that you can in order to save for that nice car you wanted in the future? All good things come with sacrifice, and your financial goals are no different. Look at your finances logically; do the research before you make any big financial decisions.',
    reversed_finance_en: 'You may not have been very disciplined with your finances lately, and have overspent, purchased many useless things, or have invested in things that are not producing returns for you. This may make you a bit desperate, but make sure you’re not tempted to recoup your losses through lazy or scheming methods.',
  },
  'pentacles-1': {
    astrology: '',
    yes_no: 'yes',
    upright_general: 'The aces in the tarot are all indicative of new beginnings. When you draw any of them, it means that you are at a point in your life where a new cycle is beginning - you are about to start afresh.',
    reversed_general: 'Though the Ace of Pentacles usually heralds an opportunity of some sort that would lead to great gains, to see it reversed can mean that this might be a poor investment, requiring much more resources than you had initially reserved - or alternatively, you might be missing your chance.',
    upright_love_en: 'A love that is loyal, lasting and practical is suggested by this card. The pentacles are related to the element of earth, which gives relationships a steady, generous, and reliable quality. Couples may find that their relationships give them a feeling of stability and security, and its influence gives them the confidence to take risks and explore. This gives lovers a feeling of independence, and allows each to thrive as individuals, while bringing more back to the relationship. Relationships may feel prosperous and abundant, and you and your lover may feel lucky and privileged to enjoy life together. If you’re single, make sure to take care of your practical life as well, as this will give you the foundation you need to find a love that can flourish.',
    reversed_love_en: 'The reversed Ace of Pentacles Tarot Love Meaning can suggest that a relationship that once gave you a sense of stability may instead be making you feel anxious and vulnerable. There may be concerns about finances that are creeping into the relationship, which can make the two of you feel unstable. Sometimes, this can be alleviated with an honest discussion and a game plan moving forward. Other times, the material or practical worries that you are dealing with now can be temporary, and solved with some careful budgeting. If you’re not in a relationship, be wary of people that seem selfish, greedy or willing to take advantage of you. This card can also simply signal missed romantic opportunities.',
    upright_career_en: 'New opportunities are available to you now, that can secure you a better job, or a higher position in your existing company. Should you take your chances, and work hard, you may be rewarded with a promotion, a business venture, or a job that truly fulfills you. Since it’s an Ace, this card signals beginnings, and these changes can mark the start of a new adventure or era for you. Good energy is coming your way; you should welcome it like a breath of fresh air.',
    reversed_career_en: 'Did you feel like you missed your chance to get that promotion you have been coveting? There is likely to be some sort of feeling of instability or missed opportunities with the reversed Ace of Pentacles. You may not feel like you’re doing well in your job, and you may be paranoid about getting fired for poor performance. Some of this may be impostor syndrome, but some concerns may be real. You’ll need to take a realistic look at yourself. You may also be feeling as though you haven’t spent your time wisely, and made some bad decisions in your career path. You haven’t invested in a career that has brought you material and emotional rewards. It’s not too late to change that; think more about what you’d like to do.',
    upright_finance_en: 'What investments are you making towards your future? The Ace of Pentacles signals financial opportunities or new financial journeys. Consider this card as a seed; you are being given the chance to take this seed and grow it into something that can sustain you in the long-term. Try and make the most of it, by learning more about your finances, or putting away some savings for the future. If you’re really lucky, this card can also signify some kind of windfall or financial gifts coming your way.',
    reversed_finance_en: 'If you haven\'t been focusing or looking at your finances recently, now may be the time. Poor planning may have meant that you have made some bad financial decisions. This can be a time of scarcity for you; you’ll have to learn how to pinch pennies in order to make it through. At worst, this can indicate a financial emergency; you may not be ready for it.',
  },
  'pentacles-2': {
    astrology: '',
    yes_no: 'neutral',
    upright_general: 'The Two of Pentacles is a card about balance - the coins are displayed in a manner that is precarious, any small change in wind or weight can tip and send them falling. For those that may have more coins to go around, they can afford to be less careful, but at this moment things may be tight. Wealth too, is a kind of energy, and it is the kind whose goings in and goings out are easiest and most tangible to see.',
    reversed_general: 'When the Two of Pentacles is in reversed position, it can mean that you are trying to juggle much too many things in your life. You need to take at least a short break to eliminate the stress. In case you are feeling that you can’t handle everything, you need to consider your own well-being and provide yourself with a time to breathe. In your work, the Two of Pentacles reversal can be a positive omen. Avoid committing to a lot of things since it will overwhelm you.In your finances, you need to learn how to live in your capacity. The Two of Pentacles reversal meaning reminds you to be aware of your income and expenditures since overspending can become a large issue, especially when you are being pulled in many directions.',
    upright_love_en: 'You’ll need to put on a balancing act with the 2 of Pentacles tarot love meaning. This card generally appears when you have many responsibilities you’ll need to take care of, and love may be the last thing on your mind. You may be feeling strained, juggling your relationship, career and family issues. All things require effort, and if you consider your relationship important, be careful to not neglect your partner. If you’re single right now, you may have to make some careful calculations about whether you are ready practically for love right now. You may need to decide what is most important to you, and make some choices to prioritize or de-prioritize romance.',
    reversed_love_en: 'You may find it difficult to keep your balancing act going, when the reversed 2 of Pentacles appears in a love tarot reading. With so many conflicts and demands on you, you may not even know that your partner is feeling neglected. It seems like everything is a bigger priority than they are, and there may be some resentment as they feel they are being taken for granted. If you’re single, this card can suggest that you may have to make a choice between two potential lovers, or that you are too busy and overwhelmed to make romance a priority in your life right now. Take your time; return when you are ready to make room in your busy life for love.',
    upright_career_en: 'You may be juggling many projects right now at work, when you draw the 2 of Pentacles in a career tarot reading. This is likely to be a more hectic time than usual, and things are either dumped on you at the last minute, that weren\'t’ meant to be your responsibility, or you have been accepting them in order to attain a better position. Others may be impressed by how much you’re able to handle, and just how resourceful you are. Ideally, this is just a temporary state. Be wary that you don’t accept more work than you can handle, or that coworkers and bosses get used to giving you all the work that nobody wants to do. If this continues, make sure you get compensated adequately for it! Sometimes, this card can also point towards balancing your career goals with other aspects of your life.',
    reversed_career_en: 'Are you taking on too many projects right now? Have you been just saying “yes” when your boss asks you to do something, even though you don’t have the time? Deadlines may be looming, and the pressure is ever increasing. Your work life can be creating considerable stress for you now. Now is the time to stand up for yourself, ask for help, renegotiate deadlines and prioritize your work. If you’re not careful, things could be falling through the cracks, creating more trouble for you. You are only human, and the faster your boss or colleagues understand this, the better it is for everyone.',
    upright_finance_en: 'The 2 of Pentacles suggests that you’re working hard to make sure all your bills are paid. You may have to do a juggling act right now, as things can be rather tight. Sometimes, the 2 of Pentacles can also point towards the need to make some important choices when it comes to your money. Things feel very uncertain and you’re likely on unstable ground right now. Everything seems to change so quickly, meaning you may be very hesitant on making that choice. Remain adaptable, and you’ll be able to come out of this situation just fine.',
    reversed_finance_en: 'Resources may be tight, and it seems that no matter what you do, you can’t figure out how to pay all your bills. As soon as money comes in, it seems like it’s immediately spent - rent, groceries, utilities, and suddenly - poof. This is not an uncommon situation unfortunately. Take a close look at your budget, or create one if you haven’t already, to see what you can cut out. Ask for a raise, or find a side project that can generate a bit of income for you. If you can, finding a professional to help you create a plan can be beneficial to you.',
  },
  'pentacles-3': {
    astrology: '',
    yes_no: 'yes',
    upright_general: 'The threes in the tarot represent the successful completion of a goal - it takes the sources of energy in the ace and the twos and adds a foundational factor, and usually involves a group of some sort. In this scenario, the upright three of pentacles meaning is that there is a successful achievement of all the requirements to pursue your business, deal, venture or any other kind of endeavor. Successful projects usually require different kinds of expertise, and at this moment, the Three of Pentacles means that all the skills required are coming together. In short, you are enjoying enjoying working together as part of a team, and also in the initial success of this bigger project.',
    reversed_general: 'The Three of Pentacles reversal meaning indicates that there is lack of team work; it shows that people are working against each other and undermining the project along the way. There seems to be too much competition between them - each person is trying to display superiority. This result to scarcity of resources - too many people are viewing their project partners as competitors.',
    upright_love_en: 'Love and teamwork can come hand in hand with the 3 of Pentacles tarot love meaning. If you’re in a relationship, you may find it particularly pleasurable to work on projects together with your lover; couples can learn more about one another and deepen their trust by developing plans for the future together, working on their home, or collaborating on creative projects. By coming together as a team, the two of you are likely to also feel supported as partners, with unique talents and weaknesses that create a harmonious balance. If you’re single, you may find that love comes through collaboration at work or through your creative hobbies.',
    reversed_love_en: 'The reversed 3 of Pentacles tarot love meaning can point to a couple that is struggling to work together practically. While the emotions may be there, they have not translated into effort or action. All love requires work, as well as desire. Being together as a couple often means being able to trust your partner to be your teammate, and your fellow collaborator on the long journey of life. How do the two of you split chores? How do you split finances? How about emotional labor? One person in the relationship may be putting in all the work, while the other is taking things for granted. Make sure that both people in your relationship are playing the role of good teammate.',
    upright_career_en: 'The 3 of Pentacles suggests that you are pooling your experience and skills together with a larger group to accomplish shared goals. Collaboration may be very important to your success now, and it can be that your projects will require cohesion among people with very different skill sets, experiences, ideas and processes. You’ll have to work hard to make sure that these diverse opinions are all focused towards accomplishment. Keep in mind the greater goal; this will help you all come together instead of arguing. Support your teammates and trust their expertise, while sharing your own unique perspective.',
    reversed_career_en: 'When it comes to work, conflict between your colleagues and yourself may be creating stress and frustration. The people that are meant to be your partners are creating more headaches for you, instead of helping you. Coworkers or collaborators may be more self-interested than working for the greater good. There can be competitiveness for resources or attention; everyone wants to be the star. Different teams may be attempting to undermine each other rather than actually listen to what the other needs. Communication errors can be commonplace as well. The reversed 3 of Pentacles can also suggest that your studies are not going well; there may be a lack of effort or motivation to complete your goals. Are you truly challenging yourself?',
    upright_finance_en: 'When it comes to finances, you may find that working with someone with financial experience can be helpful for you now. Others may be able to help you build a budget, and get on track towards your material goals. If this doesn’t apply to you, the 3 of Pentacles may also be about simply learning more about what it takes to get your finances together. This period of learning can be very beneficial for you in the long run.',
    reversed_finance_en: 'There can be the reluctance to learn about financial matters with the reversed 3 of Pentacles. Instead of looking at your finances directly and seeing what you can do, it may be that anything to do with money or resources scares or drains you, so you would prefer to avoid it entirely. You need to put in the energy to learn about savings, the best bank accounts, credit cards and other financial products before you start using them.',
  },
  'pentacles-4': {
    astrology: '',
    yes_no: 'neutral',
    upright_general: 'The Four of Pentacles card is capable of generating both negative and positive perceptions. On one hand, the card signifies that you have successfully managed to accomplish much of your goals and you have managed to attain a significant material wealth in the process. However, on the other hand, there is a significant chance that you will start valuing things only for their material worth. You have worked hard to get to the point where you are now, and it is absolutely natural for your to desire to make sure that you remain stable. But this also has a chance to turn you into an overly possessive or greedy person who wants to ensure that no one is capable of taking away your own wealth.',
    reversed_general: 'When reversed, the Four of Pentacles veers sharply into the negative meanings of the card. Instead of being protective you become greedy, and you succumb to stinginess. You are haunted by certain fears of poverty which compels you to be nothing but materialistic. You are incredibly self-protective and defensive in terms of materialistic things, and you are not opening up to trust other people out of fear that they may be taking them away. On the other side, you might actually be spending too much money, and you need to start getting a proper hold of your actual financial resources. In any case, the card is capable of inducing both positive and negative associations, and you need to be very accountable and considerate if you get the Four of Pentacles in a reading.',
    upright_love_en: 'Your relationship can be clingy and even suffocating, with the 4 of Pentacles tarot love meaning. Relationships with this card can be filled with jealousy and possessiveness, which can slowly deteriorate even the happiest of loves. There are likely issues with insecurity or fear involved, and lovers may have to take some time to untangle these issues before they drive away their partner. If you’re single, there is likely you’re still holding onto something from your past romances; whether it is grudges, resentment or the dream of an ex returning to your life. These things need to be resolved before you can truly be open to another lover again.',
    reversed_love_en: 'Past insecurities may be healing now, allowing you or your lover to be less jealous and possessive. The reversed 4 of Pentacles love meaning can therefore signal that the relationship can move forwards without being hindered by past wounds. If you’re single, it may be that you are ready to finally open your heart to new love, and have let go of something that has prevented you from letting your romantic life flourish.',
    upright_career_en: 'You have finally found some stability in your career right now, with the 4 of Pentacles appearing in your work spread. If you’ve struggled in the past to find this stability, or if the job is new to you, it may be that you’re still a bit insecure about your role. This can make you guarded, uneasy and perhaps even paranoid. This can do you more harm than good if you let it go too far. You may find it hard to collaborate and work as a team, feeling protective of your ideas, and worried that others may get the credit that rightfully belongs to you. These things do happen, address them, but don’t let yourself be consumed by them.',
    reversed_career_en: 'The reversed 4 of Pentacles may be a little tricky to interpret. Positive associations suggest that your warmhearted and generous nature at work can be a powerful asset for you. You are readily available to help others and give credit where credit is due. Alternatively, you may instead be making risky decisions and careless of the consequences. Avoid trying to do the flashiest project, or shoot for the most ambitious, irrational goal right now, as it can land you in trouble rather than help you.',
    upright_finance_en: 'You may have recently just found some material stability, and as such you have been able to accumulate a little fortune. If you’re used to struggling, you may think about your finances a lot, trying to do whatever you can to protect this small fortune. You can be rather frugal and conservative with your money, even if it causes you a lot of extra work or distress. Alternatively, the 4 of Pentacles can simply suggest that you are saving for something big, like a car or new home, a child’s future, or your own retirement fund.',
    reversed_finance_en: 'At times, the reversed 4 of Pentacles can signal that you’re slowly learning how to open up your pocketbook. You may generally be frugal, you are learning that it can feel good to give to others, or use your money in helpful ways. You may be donating or sharing your resources with family or friends, or purchasing things based on quality instead of price. Other times however, you can be rather careless about your money; this can make you an easy target for thieves, or shady financial schemes. Be on the lookout.',
  },
  'pentacles-5': {
    astrology: '',
    yes_no: 'no',
    upright_general: 'Whenever the Five of Pentacles shows up in a reading, it suggests a time of hardship and insecurity. The meaning of this card can be deep loneliness, illness, poverty or loss. Your status might take a turn for the worse in the near future. There is a chance that you will lose something significant, whether it is financial wealth or an important item. Deterioration of your health might be already ongoing or be very sudden.',
    reversed_general: 'Unlike the upright version, the Five of Pentacles reversal meaning can be a positive one. The snow is now on top, which represents brightness coming into your life. The stained glass now symbolizes a passageway with the Pentacles serving as the light at the end of the tunnel. The reversed Five of Pentacles means change is coming. When drawing this card, it can mean that the worst is now over, but don’t expect changes to happen overnight. It will take some time before you can recover, and find strength once again. This means you will be able to regain stability in terms of property, health, relationships, business, or finances. Slow recovery from illness can be indicated by the Five of Pentacles reversed as well. You will be able to find a treatment that can lead to recovery. If you are caring for someone, then it can mean that help will be made available, whether it is financial or practical assistance.',
    upright_love_en: 'It may seem right now that you’ll never find the love you are searching for with the 5 of Pentacles tarot love meaning. Singles may be in a period of despair, ready to give up their long search for the right partner and give into their loneliness. Unfortunately, this attitude can be a self-fulfilling prophecy. Feelings of isolation or scarcity can appear in existing relationships as well, whether it comes from within one’s partnership or outside of it. Lovers may find it difficult to communicate honestly, or be emotionally close to their partners, creating a wall between one another. Depression may be an issue as well. Sometimes this card can signal a lack of financial security, creating strain in your romantic relationships. This may be a difficult time, but it is more important than ever to draw close together, instead of pulling apart.',
    reversed_love_en: 'A period of isolation, rejection and despair may be coming to an end. The reversed 5 of Pentacles tarot love meaning can suggest that your relationship or your dating prospects are improving again, as you have worked to prevail over difficult circumstances. As struggles are lightening, you can make steady progress in rekindling your relationship, or opening yourself up to new people.',
    upright_career_en: 'The 5 of Pentacles appearing in a career or work context can spell trouble. You may be going through a period of hardship at work, perhaps through losing a job, or feeling alone and abandoned at work by colleagues or bosses. Others may treat you like an outcast, and you may struggle with office politics and being social. If you’re a business owner, you may also be struggling. All these issues may be severely affecting your mental health, and it can be a downward spiral. If you believe that this situation won’t change, you may want to start looking for another job.',
    reversed_career_en: 'If your career or business has been going through problems, the reversed 5 of Pentacles can suggest that there is a light at the end of the tunnel. Things are likely to return back to normal. Difficult situations can now be healed, or you may have found another job that values you for what you do. Look out for any opportunities.',
    upright_finance_en: 'Financial hardship is represented by the 5 of Pentacles. You’ll need to pinch pennies and stretch your dollars right now, since money feels very tight. Sometimes, in the worst case, this card can also suggest material loss, so you may also be dealing with debt, bankruptcy or evictions.  so expect money to be tight when it appears. Whatever the situation, don’t let your pride stop you from asking for help. Look into soup kitchens and charities if you need to; there should be no shame in doing so, we all go through tough times financially. If you can, you may want to start putting together an emergency fund.',
    reversed_finance_en: 'Slowly, bit by bit, you may be recovering from a financial loss. You may be paying back debts, or rebuilding an emergency fund after a big loss. Keep up the effort, and you’ll likely find yourself in a place of financial stability again. The worst is over.',
  },
  'pentacles-6': {
    astrology: '',
    yes_no: 'yes',
    upright_general: 'The Six of Pentacles means is that you are in a position where you have a good relationship with your income. Like the main figure in the card, the amount of money that you bring in and your expenses are balanced well, and you are fortunate enough to not have any stress. You are also grateful for all that you own and can happily share your wealth with others. As you can tell from the imagery in the card, the Six of Pentacles can be about charity. You can either be the man giving away money to the needy, or a beggar gratefully receiving what you need from wealthy donor.',
    reversed_general: 'The Six of Pentacles reversed can suggest that charity can be one-way. If you have loaned someone money, you should not be expecting your money to be paid back, or your favor to be returned in the future. You should be cautious about the people you are lending money to, especially if you are not financially stable. You could also have problems with spending and giving away more than you can really afford. The Six of Pentacles reversed can also warn you about the debts that you have. This could mean that you are in over your head and it is going to come back and be a major problem in the future. You should also be careful of entering business endeavors during this time because you could end up with a huge loss, instead of getting a return on your investment. The last Six of Pentacles reversal meaning is that there is selfishness related to giving and charity. This may mean that you are willing to give others in a way that is not to benefit them, but to benefit yourself. You should be cautious that you are not just being charitable to prove you are giving or generous to others. The source of generosity should be selfless, not selfish.',
    upright_love_en: 'Kindness and generosity characterizes your relationship, with the 6 of Pentacles tarot love meaning. Your partner may be very supportive of you emotionally and financially as you are pursuing your goals. You may be going to school, or starting a new business venture, but perhaps a bit fearful on what the risk could do to your partnership. But you may find a happy surprise in your partner’s willingness to help you achieve that goal. Remember however, to keep the partnership balanced. Be giving and reciprocate to your partner in other ways, to show how much you appreciate them. In this way, your relationship thrives. If you’re single, you may find that you or another person’s generosity with energy, time or resources can lead to love.',
    reversed_love_en: 'Power dynamics and imbalances can create big problems within your relationship with the reversed 6 of Pentacles tarot love meaning. Should one partner always be giving and giving, and the other receiving, one person can feel taken advantage of and resentful, while the other can feel trapped and dependent. It is always important to maintain a level of independence and self-sufficiency in the relationship. The dynamics here must be corrected again in order for this relationship to become healthy. Those who are single may want to be wary of partners that create this power imbalance; avoid being too generous or too dependent on your romantic relationships.',
    upright_career_en: 'If you draw the 6 of Pentacles in a work tarot spread, there may be a more senior person at your workplace that is ready to help you achieve your career goals. This mentor can be very generous with their time and their energy in helping you succeed, and attain more skills and a higher status within your career path. The 6 of Pentacles can also signal that your workplace puts a high value on your contributions. If you’re looking for a new job, this card can suggest that the changes will be even better than you expected. If you own your own business, this card can suggest investors, or folks that are willing to help you grow your business.',
    reversed_career_en: 'Beware of people in your workplace that can seem helpful and generous, but may have hidden agendas. Someone may abuse their position of power, or offer you help. But these create the circumstances for feeling that you \'owe\' them later on. They may ask you to do something at the cost of your honor. If you’re someone with power, remember to give your help without asking anything in return; you must have memories of what it was like when you were younger. If you’re someone that is receiving help, be sure not to abuse that help. Are you sucking up to someone whose position or status can aid you? This may be more obvious to others than you think. Avoid that temptation and remain honest with yourself and others.',
    upright_finance_en: 'You’re likely to find much generosity within your community at the moment. If you’ve had a dream to start a project or a business, you may find many people willing to help you make this a reality. Go out and ask, pitch your idea, create a kickstarter campaign, tell people what you want to build. Your passion is likely to inspire others to help in whatever way they can. On the other hand, you may find that you’re in the position of giving others your material support right now. You may now be in a comfortable position where you can afford helping others.',
    reversed_finance_en: 'If you’ve been looking for financial help, it may look bleak right now. It doesn’t seem like there are others that can offer you what you need. If you do find someone willing to help you, be cautious. Check that your loan terms are fair, or that gifts don’t come with strings attached. Otherwise, you may find yourself in bigger trouble than you are now. If you’re someone who is in the position to give, avoid feelings of resentment, or taking advantage of your financial comfort. Alternatively, you may be the one being taken advantage of; ensure that your financial assistance goes to who you want it to go to by giving it directly. Beware of scams that prey on kind hearts.',
  },
  'pentacles-7': {
    astrology: '',
    yes_no: 'neutral',
    upright_general: 'The meaning of the Seven of Pentacles relates to investment and effort. It follows the Six of Pentacles which refers to the end of financial or material hardship. If you have been putting in time and effort in your work, it signifies that your efforts are paying off and they are going to pay off in the future as well. If you are looking to invest, the Seven of Pentacles suggests that you are ready to put in a lot of effort, time and work into whatever you want to achieve. It reaffirms you of your long-term vision and helps to show that you are not confined to seeing results in the short term only. It shows how much you value the investment because of the effort that you are willing to put in.',
    reversed_general: 'The Seven of Pentacles reversed means that your returns may be scattered for now. It could also mean that the rewards of your labor are not as significant as you thought. The advantage of this is that it shows that you know when to stop investing your time, money or energy in a particular project. You, therefore, need to reevaluate your choices, and figure out where you should put your resources. The Seven of Pentacles reversal meaning could also be applied to relationships and the effort and emotions that you have invested.',
    upright_love_en: 'With the 7 of Pentacles tarot love meaning, love can be slow to flourish. For those that who are single, long term friendships can slowly turn into romantic love. Friendships that you may make now can also be the seeds of something more. Love can sometimes be exhausting, but the rewards that come after are invaluable. If you’re in a relationship, life together now may seem tedious or grueling. Perhaps in order to be together, your partnership may require working out long term plans or creating compromises in your routine or finances. But this card is also a reminder that love isn’t always passionate romances and outbursts of emotions, but it is also partners putting in the work every day to remain together within an ever-changing world. Over time, all the tedious moments, all the hard work, will be something to be looked back at fondly. After all, these were the things that let your love grow to something as beautiful as you have now.',
    reversed_love_en: 'You may be ready to throw in the towel, when the reversed 7 of Pentacles appears in a love tarot reading. You may have toiled for love and romance, putting in so much effort, only to see little come from it. It can suggest a certain amount of impatience, when one certainly cannot force love to magically arise. Some loves come suddenly, and others can take time; we can only be patient and hope for the right moment. Whether reversed or upright, the 7 of Pentacles tarot love meanings signals slow but steady progress, so much so that you may not even notice it. But keep nourishing that love, and one day you may find it having a profound influence on your life.',
    upright_career_en: 'Regardless of whether you see results or not, the 7 of Pentacles signals that progress is being made. It may be slow, but every day your work pays off. It can be helpful now to take a closer look at your achievements, and look at what is working and what isn\'t. This may help you understand where to focus your energy, and what strategies you can have going forward. If you own your own business or are self-employed, taking the time now to evaluate your work will be helpful, and can create a firm foundation for future growth.',
    reversed_career_en: 'Are you putting way too much effort at work? Or are you not putting in enough? The reversed 7 of Pentacles can signal some kind of imbalance when it comes to your career. It seems that regardless of the answer, nothing you do (or don’t do) seems to change anything. Results are minimal. Spending too much time at work can sometimes be counter productive, like overwatering a plant; giving too much attention to something can kill it. On the other hand, you may be too distracted to focus on one particular strategy for success. With your efforts being diluted, nothing much is likely to come from them. You’ll need to focus on one method, and do the research to make sure it works.',
    upright_finance_en: 'You may be reaping the fruits of your labor right now, with the 7 of Pentacles. Things that you have been incrementally putting effort and time into can finally be showing progress. Before you know it, you’ll be likely to find that you’ll be able to enjoy the rewards.',
    reversed_finance_en: 'In finances, the 7 of Pentacles in reverse can symbolize investments of time, energy and resources are not paying off. You may even suffer losses. Even when you are working hard on your dreams, you may not get rewarded. Negotiate for what you’re worth.',
  },
  'pentacles-8': {
    astrology: '',
    yes_no: 'yes',
    upright_general: 'This card indicates a time that you have to work hard and focus entirely on your tasks. This is not necessarily a negative situation, but this means that you must really strive to be the best. The task that you need to accomplish can be personal or professional. No matter what type of task it is, do not be afraid to ask for help when things get overwhelming. The Eight of Pentacles refers to the efforts that you undertake. There is a possibility that there will be a lot of things that you need to address. Hard work is essential, but you still need to find a balance.',
    reversed_general: 'When reversed, the Eight of Pentacles signifies something similar to the upright position, but the tasks may be even more demanding. This means that you need to execute swiftly and with great care if you want to be happy and successful with this outcome. In terms of work, the Eight of Pentacles reversed refers to the importance of impressing your employer through your diligence, dedication and intelligence. Never avoid any task or responsibility in your work - or else this can damage your reputation. In love, the Eight of Pentacles may reveal that both of you may not be prepared to handle the responsibilities to make your relationship work',
    upright_love_en: 'If you think about it, loving someone is like cultivating a skill. It requires ever increasing amounts of empathy, compassion, patience and also curiosity and the desire for self-improvement. Be proud for what you have accomplished, and the lessons that you have learned. If you’re in a relationship, you may find that your lover is still surprising you, even all the time you have spent together. There are still new facets of them that you discover every day, if you look hard enough. Maybe you fell in love with them for their sweet kindness, only to see their passion erupt when they are confronted with danger, or something that violates their principles. Learning to appreciate those new sides of them are something that can deepen your love for one another.',
    reversed_love_en: 'You can’t cut any corners, or take any shortcuts when it comes to love. The reversed 8 of Pentacles tarot love meaning is a reminder that the effort we put into our relationships and our love life matters. We can either devote ourselves to them, and patiently watch it flourish under our care, or we can take it for granted, and let it eventually die. This means that your relationship or romantic life may require a lot from you right now. It may be that your partner may need you to step up; have you been doing your part of the chores? Have you been expressing your affection? Have you shown your love as much as you have been accepting love? Try and make sure that both your needs are being met.',
    upright_career_en: 'When it comes to work, your dedication and commitment to improving your skills is likely to be rewarded. Career goals can be met now, and you may be achieving a new level of skill and expertise. Others may appreciate how much you’ve grown, and can look up to you as a leader in your field. Sometimes, this card can also indicate a promotion. If you’re in the process of starting your own business, your craftsmanship and care for your work will lead towards great success and profit. Keep your skills sharp, and remain curious. If you’re currently in a period of study, your talent may impress others right now.',
    reversed_career_en: 'You may be stuck in a tedious job that you hate right now. Having little enthusiasm is likely to affect how much effort you put into your job, and it’s likely that your work suffers. You may feel like you are in no hurry to make any changes however. The work you are doing feels bland, and you are no longer concerned with improving your skill set. Instead, you can just be dragging your feet, waiting for the time to clock out and collect a paycheck. Employers right now may feel that you lack the experience needed for new positions. If you have a business, quality standards may fall, and your reputation may be damaged as a result.',
    upright_finance_en: 'With the 8 of Pentacles, you may be looking at financial rewards for your dedication and your commitment to your field. Sometimes a promotion may be indicated, or more business if you’re self-employed. If you’ve been careful with your finances, you may be slowly becoming more financially independent. When you enjoy your success, you may have memories of how difficult things were before. Give yourself a pat on the back, and let those thoughts motivate you.',
    reversed_finance_en: 'Even managing your finances takes work. You may be a bit careless with your finances, meaning overspending, or perhaps total ignorance. When you need the money, you may find yourself in a bit of a bind. It’s better to face these matters and take care of them before they get worse.',
  },
  'pentacles-9': {
    astrology: '',
    yes_no: 'yes',
    upright_general: 'This Nine of Pentacles card indicates that the querent has reached a stage in their lives where they are confident, independent and self-sufficient. Through hard work, this person is now ready to enjoy money, leisure and material comfort. The difficulties that were faced in the earlier journey of the pentacles appear to be over. The Nine of Pentacles conveys not only joy, but also the feeling of security and freedom that material wealth can bring. Looking back, the querent can now celebrate the difficulties, the struggles, and the hard work that lined her path. Her previous challenges gave her the wider perspective she needs to understand the spiritual value of her success. Knowing how difficult it was to get here, she intends to enjoy every single day that is given to her.',
    reversed_general: 'The Nine of Pentacles reversed can be indicative of suffering from financial issues. It can perhaps indicate a false display of security and stability. There may be a desire here to keep up appearances - to have all the finer things in life even when we cannot afford to do so. Where does this stem from?',
    upright_love_en: 'Life has been kind to you; and you may at the moment be experiencing a time of luxury, or at least, having everything that you need. Even if you’re not partnered right now, romance doesn’t seem particularly pressing to you. You may just be seeking to appreciate what you have. This quality can make you even more attractive to others; lovers found now will need to make sure that they contribute to that happiness, not take away from it. Those who are already in a relationship may find that each person has their own achievements, careers, hobbies, interests and social life; there is a healthy mix of independence and love amongst you two. Sometimes, this card can also point towards you and your lover working on your home together, and creating a space that is truly yours.',
    reversed_love_en: 'While it may look like you have it all right now, the reality may not be the case. The reversed 9 of Pentacles tarot love meaning can signal a feeling that despite having everything, your life is still missing something. Those who are single may be well aware of this; you may have a good career, stable finances, good friendships and relationships with family, but love still evades you. Sometimes, this can be unconscious; you may be worried about giving up your independence, or perhaps afraid of sharing your life with someone who will not love you for who you are, but what you have. You may not even realize that you are pushing others away. If you’re in a relationship, you may still feel guarded, despite your best efforts and desires to spend your life with this person. The reversed 9 of Pentacles asks you to open up; and address what you are fearing, so you can experience love without fear.',
    upright_career_en: 'This card suggests that you have achieved much in your career, and you are rewarded accordingly; abundance, success and financial rewards are all rightly earned. All your hard work and professional attitude have paid off, and you can now take the time to sit back and enjoy your success. Your business may be flourishing, and the profits may let you live comfortably. Sometimes, this card can also symbolize a retirement, or taking a vacation after a time of consistent work and labor.',
    reversed_career_en: 'If you’ve dealt with any failures lately, it may be because you haven’t put in too much effort. The 9 of Pentacles can suggest that you desperately desire success, but may not be ready to actually work for it. On the other hand, this card can indicate that you may have worked so hard that everything else has fallen by the wayside. Time passes quickly, and before you know it, everything can change. Take some time to review your finances, if you have a business. You need to make sure that the people that you work with are trustworthy. Take time to check your legal documents to be safe as well.',
    upright_finance_en: 'The 9 of Pentacles suggests prosperity, stability and material security. If you’ve invested your time or resources into something, it may be time for you to enjoy the rewards. Your social status may improve because of this newfound comfort. Since this card is also tied to the land, you may also be in the process of purchasing some property.',
    reversed_finance_en: 'You may be overspending right now, and you may have to deal with some serious financial recklessness. Impulse buys and spending beyond your means can lead to regrets. You may also be financially dependent on another person. This card is also a warning to avoid engaging with shady business deals, or get rich quick schemes. These can often lead you to financial ruin.',
  },
  'pentacles-10': {
    astrology: '',
    yes_no: 'yes',
    upright_general: 'The Ten of Pentacles deals with permanence and satisfaction. The card shows that everything you have put your efforts into for a long time will pay off in the future. It suggests that everything will work out well in the end - for you have always kept the long term picture in view, choosing to take no shortcuts. Your legacy is sure to stand for quite a long time to come. This is a relief, for the path to get here has been filled with setbacks and challenges, making this point of the journey even sweeter.',
    reversed_general: 'The Ten of Pentacles reversed meaning may be a warning about your future financial status. It could point to problems and hiccups later on in life, even though they may not currently be an issue. It could also show the faulty nature of an investment that you have put a lot of time and effort in. In general, this reversed card seems to signal that you are placing too many bets on your short-term success, while harming your long-term potential. Take a step back and evaluate whether your decisions right now will lead to more damage in the future.',
    upright_love_en: 'If you’re in a relationship, the 10 of Pentacles tarot love meaning can indicate abundance, affection and luck as a couple. From both an emotional and material standpoint, the two of you are in a strong position. It is likely that you have a strong foundation now for family, should you choose to have one. That idea may indeed be on your mind; you may be working together on moving in together, buying a house, or starting a family.',
    reversed_love_en: 'Are you placing too much importance on what your family or others think about your partner? In an effort to find love, you may be searching for outside approval as well, instead of focusing on the emotional connection between the two of you. On the other hand, there may be conflicts between your lover and your family or friends. They may find that your partner is “unsuitable”; they may not have a good enough job, they may come from a different background, they may not be the Prince Charming that your family needs to show off how well their child is doing. Conflict now can have a great effect on your partnership, and you may have to assert your boundaries instead of accepting their opinions without thinking yourself.',
    upright_career_en: 'If you have a business, you are in the process of building something that is lasting. The 10 of Pentacles can also suggest something about a family business. If you’re not a business owner, worry not - the 10 of Pentacles also signals that your job and career track is one that is quite secure and can provide for you financially in the long term. This reliable job may be in a large, traditional company with a long history.',
    reversed_career_en: 'If you own your own business, things may not be going well for you. In the worst case scenarios, it can suggest the dissolution of a company, debt, or bankruptcy. It may be time to revisit your business decisions and see what you can salvage. When it comes to careers, the 10 of Pentacles suggests that your job may be unstable, especially for the long term. You may find better prospects somewhere else.',
    upright_finance_en: 'A sudden windfall may be coming your way with the 10 of Pentacles. Since this card is related to family, it can likely come from a relative. The card can also mean that you are setting up your financial future. You may be putting together your retirement plan, building your savings, or even creating a will. In a general sense, this card signifies wealth and money that comes from family.',
    reversed_finance_en: 'Be wary of any debts you have that are piling up now. The reversed 10 of Pentacles signals big financial losses. Sometimes, the card can also signal inheritance disputes, family arguments, or conflicts about money in general. You may need to be extra careful now.',
  },
  'pentacles-11': {
    astrology: '',
    yes_no: 'yes',
    upright_general: 'When we meet the Page of Pentacles, we see immediately that she is one that is ambitious and focused. She is protected, nourished, provided for by the suit whose name she bears. Guided by it, she is deeply tied to the earth, nature, and all of its gifts. She cherishes the body, for it too is something which is a manifestation of her element. Her diligence, ambition and loyalty drives her to quickly make plans for the future - for it is there where her focus lies.',
    reversed_general: 'When the Page of Pentacles card appears reversed, it may point to your lack of focus. There is a possibility that you are being distracted with lots of things. Try to borrow the talents of this page and focus your mind before moving on the next thing.',
    upright_love_en: 'The person symbolized by the Page of Pentacles is ambitious, loyal and practical; they may often be seen as studious, but once you get to know them well, they can also be quite funny. Their ambition and focus means that they are hardworking. They are likely to be as dedicated as they are to a lover, as they are to their goals. Their quiet demeanor may make them hard to notice at first, compared to other folks that may be more out going.',
    reversed_love_en: 'The reversed Page of Pentacles tarot love meaning can signal a lack of commitment and dedication when it comes to matters of the heart. Instead of focusing on long term companionship, you may find yourself easily distracted by every new person. There’s nothing wrong with this, but make sure set clear expectations and not lead potential lovers on. Other times, this card can point towards an ambivalence to dating. If you’re in a relationship, this Page can suggest a relationship that has become stagnant and monotonous. There can be frustration stemming from this boredom. You and your partner will need to work hard to remain together and remember why you two fell in love in the first place.',
    upright_career_en: 'You may now be building a strong foundation for success. You’re likely to be creating your goals, planning strategies and putting those plans into action. You’re not afraid to put yourself out there in order to achieve your wildest dreams. It is likely that there are lots of work opportunities available for you, so go ahead and reach for them! Sometimes, this card can also suggest that you are going through or looking to start a higher education program. Study hard; if you do the work, you’re likely to do an amazing job.',
    reversed_career_en: 'Bad news can be coming when the Page of Pentacles is reversed. You may be neglecting your work or your studies right now, meaning that your foundations for success is feeling rather shaky. You may day dream about being successful, but when it comes to putting in the work, you can be lazy and unmotivated. Sometimes this comes from unrealistic ideals about success. We often see the result, but not the back-breaking work it takes to get there. Be realistic about what you want to achieve, and whether you are willing to sacrifice to get there. If you’re currently in school, you may not be doing well, or putting in your best effort.',
    upright_finance_en: 'Good news is coming in regards to your finances. The Page of Pentacles promises good rewards, so long as you take the steps to plan your future. Do the research, stay on track with your budget, and you’ll be seeing that your effort will make a big difference in your material situation.',
    reversed_finance_en: 'The reversed Page of Pentacles can bring bad financial news, or sometimes material insecurity. You may be anxious and worried when it comes to finances. Sometimes this card can also suggest being irresponsible with your money. While it can be scary, it is important to know exactly what is going in and what is going out of your bank accounts. Don’t avoid this; make sure you spend within your means. Savings in case of emergencies can be helpful.',
  },
  'pentacles-12': {
    astrology: '',
    yes_no: 'yes',
    upright_general: 'The Knight of Pentacles is about the daily tasks and the responsibility that one has to gain through a specific project. This knight has the patience to accomplish all his given duties and is considered by others reliable and committed to his work. To see this card is an indication that there is a need to be trustworthy and reliable.',
    reversed_general: 'When the reversed Knight of Pentacles shows up in a reading, the traits that were once positive in the upright position are now taken to the extreme. You may feel stuck in your own routine, and bored of everything that surrounds you. You may desire a change of scenery in order to avoid this tiring repetition. The Knight of Pentacles reversed could also indicate that you have totally ignored many serious aspects of your life. Financial or personal issues are often be neglected in favor of work matters when this card appears reversed.',
    upright_love_en: 'The Knight of Pentacles is hardworking and diligent. He is patient, reliable and steady, though sometimes deeply absorbed in his work. They prefer not to take risks in love, as well as elsewhere in their lives. It is difficult to get this person to change their minds; which means they can be stubborn, but also a very trustworthy and dedicated partner. The Knight of Pentacles tarot love meaning can also suggest a relationship that is deep and reliable, but not very exciting. If you’re at a point where you would like commitment, stability and security in your love life, this card can be a welcome sight. It indicates a partnership in which both of you will be working towards your long term goals together.',
    reversed_love_en: 'It may be that your love life is getting rather dull and stale lately. You may feel like a homebody that prefers to enjoy their time alone rather than take any emotional risks, and face possible rejection amongst others. If you’re in a relationship, you may feel a bit desperate for change. It may be that one of you spends so much time at work, or all their energy on practical, financial or career matters that they don’t prioritize the relationship. Make sure that the two of you carve out time in your busy lives to just be with one another, or try something spontaneous to bring a much needed breath of fresh air into your partnership.',
    upright_career_en: 'When it comes to work, the Knight of Pentacles suggests ambition, drive and focus. You are very much committed to your goals, however far away in the future they may be. It’s likely that you’ll do anything you can do achieve them, so you’re prepared to put in the hard work and the blood, sweat and tears. You have a slow and steady approach, and believe that hard work is rewarded. Should you be searching for a job, you’ll need to prove your reliability and your dedication to a prospective employer.',
    reversed_career_en: 'Are you lacking in ambition? Do you find that you have little motivation when it comes to work? One possible meaning of the reversed Knight of Pentacles is that you’re not working hard enough to make your career dreams come true. Alternatively, you may be so obsessed with your career goals, that you sacrifice everything else to achieve them. Your love life may be in shambles, you may barely meet friends, and have all but forgotten close family members. Do you still remember how to have fun? It may be better in the long run to develop a better work-life balance. Don’t burn yourself out.',
    upright_finance_en: 'The Knight of Pentacles builds his financial future slowly, but steadily. He avoids taking big risks, and prefers things that are as safe and reliable as he is. You may be budgeting and slowly saving for a long term goal. Some frugality may be helpful now.',
    reversed_finance_en: 'Wasting resources can be signaled by the Knight of Pentacles reversed tarot card meaning. Instead of being careful, you may be very impulsive with your purchases, finding out later that what you bought wasn’t what you were hoping for or needed. Try and be more careful. Before you buy that big ticket item, do all your research.',
  },
  'pentacles-13': {
    astrology: '',
    yes_no: 'yes',
    upright_general: 'The Queen of Pentacles represents both a down-to-earth woman who plays many roles to ensure that she keeps her family happy. She knows how and when to show love - keeping an orderly home, cooking comforting meals and takes care of the children. But do not mistake her for being only a homebody - alongside all these motherly attributes, she can plan business ventures and execute her plans successfully. It is through her naturally talented business sense that she is surrounded by such luxury. She is quiet and does not like disclosing her financial accounts, fearing that it could bring more complexity to her life, which she desires to keep rather simple. She may have a secret bank account that nobody knows about - for she may choose to be careful, vigilant and self-sufficient.',
    reversed_general: 'When the Queen of Pentacles becomes disconnected with the energy of her suit, she can become someone who is completely self-absorbed. Gone is the upright generosity in her suit, she can be selfish and even envious when others successes seem greater than hers. Upright, her home is usually a sanctuary for her guests, but reversed it may instead be slovenly - she loses the ability to take care of herself and her surroundings. Her focus on the material may manifest negatively, making her greedy, and yet lacking in her sense of duty and capability. How can she ground herself again, how can she re-enter the sacred relationship she naturally feels with the earth and all its living creatures?',
    upright_love_en: 'The Queen of Pentacles is a worldly, practical, generous, hardworking and warm person, who has a talent both for business as well as a love of comfort and luxury. She enjoys making her home welcoming, always delighted to have guests. Single folks right now should be in a wonderful position to choose a partner that truly brings something into your life. You’ll likely have high standards, and hope for someone who has the same level of dedication, commitment and ambition as you do. If you’re already in a relationship, you may find that the two of you are enjoying a stable, fruitful and prosperous time in your life together. You can certainly afford to indulge a little and treat yourselves.',
    reversed_love_en: 'This person can be selfish and shallow, easily coveting what others have. Their own insecurity makes it so that they are often jealous and possessive, and this can extend to their lovers and relationships as well, so that they are controlling and often treat their partners more like objects to show off rather than having any serious strong affection or love for them. If you’re single, the Queen of Pentacles tarot love meaning can signal that you may need to take some time on developing your own confidence and healing any insecurities you have before entering a relationship with another person. Avoid getting into relationships for the wrong reasons; whether it’s for status, money or simply because you don’t want to be alone. Should you be in a relationship, avoid treating your lover as something to have; lovers need to consider each other partners with their own feelings, needs and desires, and be more respectful of one another’s autonomy.',
    upright_career_en: 'When it comes to all things career oriented, the Queen of Pentacles tarot card can bring great success. She is a talented businesswoman who is practical, organized and very capable in anything she puts her mind to. In your life, she can appear as a successful person, who may make a great mentor, colleague or business partner. If you do choose to collaborate with her, you’ll find that her vast skill set will be invaluable to your career or your professional projects. If she offers advice, listen to it; she cares for you, and will help you accomplish your goals.',
    reversed_career_en: 'Your career can be a bit chaotic right now, meaning that you may find it hard to get a stable income. Don’t be afraid to do as the Queen of Pentacles does, and get your hands dirty. Let her confidence in her capabilities inspire you. As a person, she may symbolize a colleague or a business partner, but one that may be lazy or terrible at managing her tasks. Be cautious, as she may create more problems that you would otherwise not need to solve.',
    upright_finance_en: 'The Queen of Pentacles offers abundance, success, and material security. You may find that after a period of hard work, you have all that you need to feel comfortable. This card represents a responsible person, who knows how to balance enjoying life’s pleasures, with practicality, frugality and good taste. She’ll always look for a good deal, but will never compromise on quality.',
    reversed_finance_en: 'The reversed Queen of Pentacles may be terrible with her finances, making it easy for her to mismanage her money. This card can suggest a time when you are being too materialistic or shallow. Avoid hoarding cash or objects as a means of quieting your insecurities.',
  },
  'pentacles-14': {
    astrology: '',
    yes_no: 'yes',
    upright_general: 'When we meet the King of Pentacles, we feel immediately his regal and generous presence. He is a provider and a protector, for under his care is a flourishing and abundant kingdom where its citizens are prosperous and encouraged to grow. He is naturally responsible and reliable, and through the wisdom granted to him by his suit, he has grown all that he has acquired from practically nothing. To see him in the cards is to envision success - one that was won by earnest work.',
    reversed_general: 'When reversed, the King of Pentacles falls from his throne. Once the king of a prosperous kingdom, it has been taken away from him, or lost. Disconnected from the energy of his suit, he may have been impatient, he may have been too indulgent, he may have gambled too far and overstretched himself, he may have sought shortcuts that led him to ruin. He may become too focused on the material, only understanding the cost of things, and never their value.',
    upright_love_en: 'Successful, generous, dependable and protective, the person represented by the King of Pentacles makes for a great partner, parent, and provider. He is demonstrative of his love through action instead of words, and looks to create a stable and loving home for his family. If you meet this person, they may be slow to make a commitment, but this is only because they take love very seriously, and need to truly understand you before taking any next steps. While not representing a person, the King of Pentacles can suggest a time in your relationship which is secure and stable. The two of you will be very comfortable, both emotionally with each other, and materially. You may have worked very hard in the past to enjoy your current standards of living, and you can now relax.',
    reversed_love_en: 'Reversed, the King of Pentacles is stubborn, conservative, greedy and materialistic. They may do practically anything to get their hands on more resources; so be wary of characters in your love life that may only be using you. On one hand, this person may be irresponsible and unreliable, choosing to gamble away their resources. On the other hand, this person can use their material means as a way of controlling their partner and their family. If this doesn’t signal a person in your love life right now, the King of Pentacles tarot love meaning can suggest a period of emotional or financial insecurity, jealousness, manipulation or coercion.',
    upright_career_en: 'In a professional context, the King of Pentacles can be an outstanding indicator of a successful business venture. When it comes to your work and your career, this King achieves his highest ambitions and has a great reputation amongst his colleagues. This card can additionally indicate that someone with more experience will mentor and encourage you in your chosen field. This person will have lots of experience, and can give you much needed support, and sometimes even recommendations to new jobs, or promotions.',
    reversed_career_en: 'When it comes to work, the reversed King of Pentacles can signal unsuccessful work projects, or at worst, the closing of a business, or the loss of job. There can be a lot of instability when it comes to work. You may be tired of your job, and this can highly affect the quality of your work as your motivation drops. Sometimes, this card can also signal  a ruthless person at work may discourage you or try to undermine you. It is important to ignore his negativity and focus on what you need to do. Engaging with such selfish, greedy and manipulating people will only drag you down. Instead, concentrate on your own career and doing your best. If you’ve been looking for a promotion or a raise, the King of Pentacles can sometimes point to you needing more experience.',
    upright_finance_en: 'When it comes to finances, the King of Pentacles represents an achievement of a financial milestone. Perhaps you have reached a level of security that comes from being diligent and wisely saving and investing. Since this King is also generous, you may also be using your newfound wealth to support loved ones, while enjoying the luxuries that you may have missed out on while you were saving. Indulge a little, you deserve it.',
    reversed_finance_en: 'In a monetary context, the reversed King of Pentacles can suggest a financial loss, or in the worse case scenario, bankruptcy ad debt. Financial resources can be very tight now. You may have gambled away your savings, or made poor financial decisions. Alternatively, the reversed King of Pentacles can signal that you may be hoarding your resources, and your stinginess may make others think negatively of you.',
  },
};
function generateMinorArcana(): TarotCard[] {
  const cards: TarotCard[] = [];
  for (const suitInfo of SUITS) {
    for (const rankInfo of RANK_NAMES) {
      const key = `${suitInfo.suit}-${rankInfo.rank}`;
      const meanings = MINOR_MEANINGS[key] || {
        upright: '正向能量流動，積極前進',
        reversed: '能量受阻，需要重新評估'
      };
      const eKey = `${suitInfo.suit}-${rankInfo.rank}`;
      const enrichedData = MINOR_ENRICHED[eKey] || {
        astrology: '', yes_no: 'neutral',
        upright_general: '', reversed_general: '',
        upright_love_en: '', reversed_love_en: '',
        upright_career_en: '', reversed_career_en: '',
        upright_finance_en: '', reversed_finance_en: '',
      };
      cards.push({
        id: `${suitInfo.suit}-${rankInfo.rank}`,
        name: `${rankInfo.name} of ${suitInfo.suit.charAt(0).toUpperCase() + suitInfo.suit.slice(1)}`,
        name_zh: `${suitInfo.suit_zh}${rankInfo.name_zh}`,
        number: rankInfo.rank,
        arcana: 'minor',
        suit: suitInfo.suit,
        element: suitInfo.element,
        keywords: meanings.upright.split('，').slice(0, 3),
        upright: {
          meaning: meanings.upright,
          love: '感情方面展現' + meanings.upright.split('，')[0] + '的特質。',
          career: '事業上呈現' + meanings.upright.split('，')[0] + '的能量。',
          advice: meanings.upright,
        },
        reversed: {
          meaning: meanings.reversed,
          love: '感情方面出現' + meanings.reversed.split('，')[0] + '的狀況。',
          career: '事業上面臨' + meanings.reversed.split('，')[0] + '的挑戰。',
          advice: meanings.reversed,
        },
        color: suitInfo.color,
        astrology: enrichedData.astrology,
        yes_no: enrichedData.yes_no as YesNo,
        upright_general: enrichedData.upright_general,
        reversed_general: enrichedData.reversed_general,
        upright_love_en: enrichedData.upright_love_en,
        reversed_love_en: enrichedData.reversed_love_en,
        upright_career_en: enrichedData.upright_career_en,
        reversed_career_en: enrichedData.reversed_career_en,
        upright_finance_en: enrichedData.upright_finance_en,
        reversed_finance_en: enrichedData.reversed_finance_en,
      });
    }
  }
  return cards;
}

export const MINOR_ARCANA = generateMinorArcana();
export const ALL_CARDS = [...MAJOR_ARCANA, ...MINOR_ARCANA];
